import dom from '../templates/Schedule.ejs';
import {
   ControlEditor
} from "../../../editor/ControlEditor";
import {
   UrlSetting
} from "../../../core/pageAction";

import { map } from '../../../decorator/controlmap';

@map("日程安排", 'teas.schedule', 'Schedule')
export class Schedule extends dsf.Controls.Control {
   constructor(id, isPart) {
      super(id, isPart);
      this._desingerClass = ControlEditor;
      this.isPre = false;
      this._date = new Date();
      this._year = this._date.getFullYear();
      this._month = this._date.getMonth();
      this._day = this._date.getDate();
      this._curweek = dsf.date.getMonthWeekDate(this._year, this._month, this._day);
      this._nowDate = dsf.date.format(new Date(), 'yyyy-mm-dd');

      this.$pageSize = 2;
      this.$moreSrc = null;
      this.$hgyMoreSrc = null;
      this.$sourceUrl = 'dbsource/interface/dsfa/schedule/getList';
   }

   get moreSrc() {
      return this.$moreSrc;
   }

   set moreSrc(val) {
      this.$moreSrc = val;
   }

   get hgyMoreSrc() {
      return this.$hgyMoreSrc;
   }

   set hgyMoreSrc(val) {
      this.$hgyMoreSrc = val;
   }

   get sourceUrl() {
      return this.$sourceUrl;
   }

   set sourceUrl(val) {
      this.$sourceUrl = val;
   }

   get pageSize() {
      return this.$pageSize;
   }

   set pageSize(val) {
      this.$pageSize = val;
   }


   initTemplate() {
      return dom(this);
   }

   createElement() {
      super.createElement();
      this.$week = this._handlers['week'];
      this.$preweek = this._handlers['preweek'];
      this.$nextweek = this._handlers['nextweek'];
      this.$schedule = this._handlers['schedule'];
   }

   renderContext() {
      super.renderContext();
      let that = this;

      if (!that._root._isDesign) {
         that.getScheduldeInitData();
         that.$preweek.on('click', function () {
            that.isPre = true;
            that.changeDate(that.isPre);
         })
         let _roleType = localStorage.getItem('userType') || null;
         let _path = !!this.$moreSrc ? 'teas/portals/views/main.html?url=' + dsf.Base64.encode(this.$moreSrc) : 'teas/portals/views/main.html?url=' + dsf.Base64.encode('teas/cms/views/schedule.html');
         if (this.$hgyMoreSrc) {
            _path = this.$hgyMoreSrc;
         }
         if (_roleType == 1) {
            _path = 'teas/portals/views/main_strips.html?url=' + dsf.Base64.encode('/teas/xyxt/kcap/views/kcap.html?showCourseDes=1')
         }
         that._handlers['scheduleMore'].attr('href', dsf.url.getWebPath(_path));
         that.$nextweek.on('click', function () {
            that.isPre = false;
            that.changeDate(that.isPre);
         })
         that._handlers['scheduleWrap'].css('min-width', '300px');
         console.log('schedule')
      }

   }

   changeDate(isPre) {
      let date = null;
      let that = this;
      if (isPre) {
         date = dsf.date.getBeforDate(that._year, that._month, that._day);
      } else {
         date = dsf.date.getAfterDate(that._year, that._month, that._day);
      }
      that._year = date.getFullYear();
      that._month = date.getMonth();
      that._day = date.getDate();
      that.getScheduldeInitData();
   }

   initEvent() {
      let that = this;
   }

   renderReady() {
      super.renderReady();
   }

   renderComplete() {
      super.renderComplete();
   }

   getScheduldeInitData() {
      let that = this;
      let params = {
         start: 0,
         end: this.$pageSize,
         curdt: that._nowDate
      }
      let loadding = dsf.layer.loadding();
      let url = dsf.url.getWebPath(this.$sourceUrl);
      dsf.http.request(url, params, "GET")
         .done(function (res) {
            if (res.success) {
               if (res.data) {
                  that.renderPage(res.data);
               }
            } else {
               dsf.layer.message(res.message)
            }
         })
         .error(function (err) {
            dsf.layer.message(err.message);
            console.log(err)
         })
         .always(function () {
            dsf.layer.close(loadding);
         }).exec();
   }

   renderPage(data) {
      let that = this;
      let _date = [];
      let _iconStr = '';
      let _btnStr = '';
      let _scheduldStr = '';
      let _roleType = localStorage.getItem('userType') || null;
      let weekDay = ["星期天", "星期一", "星期二", "星期三", "星期四", "星期五", "星期六"];
      if (data.length > 0) {
         for (let i = 0; i < data.length; ++i) {
            let item = data[i];
            _date.push(new Date(item.sdate));
            let kqFlag = false;
            let nTimeTmp = new Date().getTime();
            let sTimeTmp = new Date(item.sdate).getTime() - 30 * 60 * 1000;
            let eTimeTmp = new Date(item.edate).getTime() + 15 * 60 * 1000;
            if (sTimeTmp <= nTimeTmp && nTimeTmp <= eTimeTmp) {
               kqFlag = true;
            }
            let _sTime = item.sdate.substring(10, 16);
            let _eTime = item.edate.substring(10, 16);
            if (item.sdate.substring(0, 10) == dsf.date.format(new Date(), 'yyyy-mm-dd')) {
               _iconStr = "<i class='icon-schedule-today icon-schedule-com'></i>";
            } else {
               _iconStr = "<i class='icon-schedule-oth icon-schedule-com'></i>";
            }
            if (_roleType && _roleType == 0) {
               let kqBtn = '';
               if (kqFlag) {
                  kqBtn = "<span class='kq-wrap' data-id='" + item.relid + "' style='font-size:12px;color:#fff;'>扫码考勤</span>";
               }
               _btnStr = " <button class='creatIkt' data-id='" + item.relid + "' data-fjzd='" + item.fjzd + "'>创建“I-课堂”</button>" + kqBtn;
            }
            _scheduldStr += "<div class='c-top-sch-item'>" +
               "                <ul>" +
               "                    <li class='c-top-sch-date'>" + _iconStr + "<span>" + item.sdate.substring(5, 10) + '  ' + weekDay[new Date(Date.parse(item.sdate.replace(/-/g, "/"))).getDay()] + _sTime + ' - ' + _eTime + "</span></li>" +
               "                    <li class='c-top-sch-til'><span>" + (!!item.item ? item.item : '') + "</span></li>" +
               "                    <li class='c-top-sch-address'><span>" + (!!item.participants ? item.participants : '') + "</span><span>" + (!!item.address ? item.address : '') + "</span></li>" +
               "                    <li class='c-top-sch-des'><span>" + (!!item.desc ? item.desc : '') + "</span></li>" +
               "                </ul>" +
               _btnStr +
               "            </div>";
         }
         that.renderMonthDate(_date);
      } else {
         that.renderMonthDate();
         that.$schedule.html("<img style='position: relative;top: 30px;left:-18px;' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>").css('text-align', 'center');
         return;
      }
      that.$schedule.html(_scheduldStr);
      $('.creatIkt').click(function () {
         let _id = $(this).attr('data-id');
         let _fjzd = $(this).attr('data-fjzd');
         let _temp = 'pkglid=' + _id;
         if (_fjzd) {
            _fjzd = JSON.parse(_fjzd);
            if (_fjzd && _fjzd.iktId !== null && _fjzd.iktId !== '') {
               _temp = 'id=' + _fjzd.iktId;
            }
         }
         that.event.trigger(schedule.itemClick, { ui: that, data: _temp });
         window.open(dsf.url.getWebPath('teas/ikt/iktgl/views/edit.html?') + _temp);
      })
      $('.kq-wrap').click(function () {
         let _id = $(this).attr('data-id');
         window.open(dsf.url.getWebPath('teas/jwgl/pkgl/pkxx/course/jumpPkkq?pkglId=' + _id))
         // dsf.layer.openDialog({
         //     title: '考勤',
         //     area: ['1200px', '600px'],
         //     content: dsf.url.getWebPath('teas/jwgl/pkgl/views/wbkq.html?pkglid=' + _id),
         //     dialogLoaded: function (layero, index, win) {}
         // });
      })
      $('.c-top-sch-item').hover(function () {
         $(this).find('.creatIkt').fadeIn();
         $(this).find('.kq-wrap').fadeIn();
      }, function () {
         $(this).find('.creatIkt').fadeOut();
         $(this).find('.kq-wrap').fadeOut();
      })
   }

   renderMonthDate(isDay) {
      let that = this;
      let _monthStr = '';
      that._curweek = dsf.date.getMonthWeekDate(that._year, that._month, that._day);
      if (isDay) {
         let _listr = '';
         for (let i = 0; i < this._curweek.list.length; ++i) {
            let item = that._curweek.list[i];
            item = dsf.date.format(item.date, 'yyyy-mm-dd');
            if (item == dsf.date.format(that._nowDate, 'yyyy-mm-dd')) {
               _listr = "<li><span class='daySelected' dates='" + item + "'>" + item.substring(8, 10) + "</span></li>";
            } else {
               _listr = "<li><span dates='" + item + "'>" + item.substring(8, 10) + "</span></li>";
            }
            _monthStr += _listr;
         }
      } else {
         let _listr = '';
         for (let i = 0; i < this._curweek.list.length; ++i) {
            let item = that._curweek.list[i];
            item = dsf.date.format(item.date, 'yyyy-mm-dd');
            if (item == dsf.date.format(that._nowDate, 'yyyy-mm-dd')) {
               _listr = "<li><span class='daySelected' dates='" + item + "'>" + item.substring(8, 10) + "</span></li>";
            } else {
               _listr = "<li><span dates='" + item + "'>" + item.substring(8, 10) + "</span></li>";
            }
            _monthStr += _listr;
         }
      }
      this.$week.html(_monthStr);
      this.$week.find('li').click(function () {
         that._nowDate = $(this).find('span').attr('dates');
         that.getScheduldeInitData();
      })

   }
}