import dom from '../templates/ExcellCourse.ejs';
import {isSupportDataPost} from '../../../core/postDecorator';
import {ControlEditor} from "../../../editor/ControlEditor";
import {UrlSetting} from "../../../core/pageAction";

import {map} from '../../../decorator/controlmap';
@map("精品课程",'teas.excellcourse','ExcellCourse')

export class ExcellCourse extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = ControlEditor;
    }

    initTemplate() {
        return dom(this);
    }

    createElement() {
        super.createElement();
        this.ExcellCourseImg = this._handlers['courseImgList']
    }

    renderContext() {
        super.renderContext();
        this.getExcellCourseInitData();
    }

    renderReady() {
        super.renderReady();
    }

    initEvent() {
        let _this = this;
    }

    renderReady() {
        // let _this = this;
        super.renderReady();
    }

    renderComplete() {
        super.renderComplete();
    }

    getExcellCourseInitData() {
        let _this = this;
        let loadding = dsf.layer.loadding();
        let url = UrlSetting.getApplicationJson;
        dsf.http.request(url, {}, "GET")
            .done(function (res) {
                _this.renderPage(res.EXCLLCOURSE);
                if (res.success) {// renderData();} else {/dsf.layer.message(res.message);
                }
            })
            .error(function (err) {
                //dsf.layer.message(err.message);
                console.log(err)
            })
            .always(function () {
                dsf.layer.close(loadding);
            }).exec();
    }
    renderPage(data) {
        let _liStr = '';
        if (data.length > 0){
            for (let item of data) {
                item.IMGSRC = dsf.url.getWebPath("res/dsf_styles/" + item.IMGSRC);
                _liStr += "<li><div class='courese-item-img-wrap'>" +
                    "<img src=" + item.IMGSRC + " alt=''>" +
                    "<div class='item-img-mask'>" +
                    "<i class='icon-time'></i>" +
                    "<span>" + item.TIME + "</span>" +
                    "</div>" +
                    "</div>" +
                    "<p>" + item.DES + "</p>" +
                    "</li>";
            }
        } else{
            _liStr = "<p style='text-align: center;padding: 10px 0;'>暂无数据</p>";
        }
        this.ExcellCourseImg.html(_liStr);
        this.ExcellCourseImg.find('li').on('click', function (e) {
            console.log(this)
        })
    }
}