import dom from '../templates/Application.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from '../../../decorator/controlmap';
@map("相关专题", 'teas.application', 'Application')
export class Application extends dsf.Controls.Control {
   constructor(id, isPart) {
      super(id, isPart);
      this._desingerClass = ControlEditor;
      this.$title = '应用';
      this.$sourceUrl = 'teas/portals/menu/getPScMenuByRoleID';
      this.columns = null;
      this.roleID = '989ba129c23340c19eac330e879e279a';
   }

   get sourceUrl() {
      return this.$sourceUrl;
   }

   set sourceUrl(val) {
      this.$sourceUrl = val;
   }

   get title() {
      return this.$title;
   }

   set title(val) {
      this.$title = val;
   }

   initTemplate() {
      return dom(this);
   }

   createElement() {
      super.createElement();
      this.$applicationList = this._handlers['applicationList'];
   }

   renderContext() {
      super.renderContext();
      if (!this._root._isDesign) {
         this.getApplicationInitData();
      }
   }

   initEvent() {
      let _this = this;
   }

   renderReady() {
      super.renderReady();
   }

   renderComplete() {
      super.renderComplete();
   }

   getApplicationInitData() {
      let _this = this;
      let params = {
         roleID: this.roleID
      }
      let loadding = dsf.layer.loadding();
      let url = dsf.url.getWebPath(this.$sourceUrl);
      dsf.http.request(url, params, "GET")
         .done(function (res) {
            if (res.success) {
               if (res.data.length > 0) {
                  _this.renderPage(res.data);
               } else {
                  _this.$applicationList.html("<img style='position: relative;top: 50px' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>").css('text-align', 'center')
               }
            } else {
               dsf.layer.message(res.message);
            }
         })
         .error(function (err) {
            dsf.layer.message(err.message);
         })
         .always(function () {
            dsf.layer.close(loadding);
         }).exec();
   }

   renderPage(data) {
      let defSty = '';
      let defW = this._handlers['applicationList'].width();
      if (!!this.columns && this.columns > 0) {
         defSty = "style='width:" + defW / this.columns + "px;'"
      }
      let _applictionStr = '';
      for (let i = 0; i < data.length; ++i) {
         let item = data[i];
         _applictionStr += `<li ${defSty} data-path="${item.url}" data-code="${item.opentype}"><a><div class="comIcon" style="background: #${item.sccolor}"><i class="icon iconfont ${item.scicon}" style='font-size: 32px;color: #fff;'></i></div><span>${item.NAME}</span></a></li>`;
      }
      this.$applicationList.html(_applictionStr);
      this.$applicationList.css({
         'height': Math.ceil((data.length / 6)) * 122 + 'px'
      })
      this.$applicationList.find('li').click(function () {
         let url = $(this).attr('data-path');
         let code = $(this).attr('data-code');
         if (code == 0 || code == 1) {
            window.location.href = dsf.url.getWebPath(url);
         } else if (code == 2) {
            window.open(dsf.url.getWebPath(url));
         } else {
            dsf.layer.openDialog({
               title: '',
               area: ['1200px', '620px'],
               content: dsf.url.getWebPath(url)
            });
         }

      })
   }
}