import dom from '../templates/RelatedToptic.ejs';
import {
    DataChoiceMetaData
} from '../../../core/metadata';
import {
    isSupportDataPost
} from '../../../core/postDecorator';
import * as ButtonPlugin from '../../../pulgins/buttons';
import {
    ControlEditor
} from "../../../editor/ControlEditor";
import {
    UrlSetting
} from "../../../core/pageAction";
import {map} from '../../../decorator/controlmap';

@map("相关专题",'teas.relatedtoptic','RelatedToptic')
export class RelatedToptic extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = ControlEditor;
        this.defaultImg = '/dsfa/teas/cms/images/defaultImg/150.png'
    }

    initTemplate() {
        return dom(this);
    }

    createElement() {
        super.createElement();
        this.relatedTopic = this._handlers['retatedTopic'];
    }

    renderContext() {
        let _this = this;
        super.renderContext();
        if (!_this.root._isDesign) {
            _this.getRelatedTopicInitData();
        }
    }

    initEvent() {
        let _this = this;
    }

    renderReady() {
        // let _this = this;
        super.renderReady();
    }

    renderComplete() {
        super.renderComplete();
        if (!this.root._isDesign) {
            //页面加载时获取数据
            this.root.event.on(PageEvent.READY, evt => {
                window.setTimeout(() => {
                    console.log('加载完成')
                }, 10)
            });
        }
    }

    getRelatedTopicInitData() {
        let _this = this;
        let loadding = dsf.layer.loadding();
        let url = UrlSetting.getReleatedTic;
        let params = {
            pageSize: 2
        }
        dsf.http.request(url, params, "GET")
            .done(function (res) {
                if (res.success) {
                    _this.renderPage(res.data.children);
                } else {
                    dsf.layer.message(res.message);
                }
            })
            .error(function (err) {
                dsf.layer.message(err.message);
                console.log(err)
            })
            .always(function () {
                dsf.layer.close(loadding);
            }).exec();
    }

    renderPage(data) {
        let _topcStr = '';
        if (data.length > 0) {
            for (let i = 0; i < data.length; ++i) {
                let image = !!data[i].shrunken ? dsf.url.getWebPath(data[i].shrunken[0].relativePath) : this.defaultImg
                _topcStr += "<li>" +
                    "           <a target='_blank' href='" + (data[i].sfwl_value == 0 ? dsf.url.getWebPath('teas/cms/template/special?code=' + data[i].code) : data[i].exurl) + "'>" +
                    "               <img src='" + image + "' alt='专题图片' onerror=\"onerror=null;src='" + this.defaultImg + "'\">" +
                    "           </a>" +
                    "</li>";
            }
        } else {
            this.relatedTopic.html("<img style='position: relative;top: 50px' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>").css({
                'text-align': 'center'
            });
            return;
        }
        this.relatedTopic.html(_topcStr);
        //this._handlers['relaTopticMore'].attr('href', dsf.url.getWebPath('teas/portals/views/main_strips.html?url=' + dsf.Base64.encode('teas/cms/views/zjxc_moreList.html')));
        this._handlers['relaTopticMore'].click(function () {
            let _path = dsf.url.getWebPath('teas/cms/views/zjxc_moreList.html');
            window.open(_path);
        })
        this.relatedTopic.find('li').on('click', function () {
            console.log(this)
        })
    }
}