import dom from '../templates/HomeWorkApprova.ejs';
import {ControlEditor} from "../../../editor/ControlEditor";
import {UrlSetting} from "../../../core/pageAction";

import {map} from '../../../decorator/controlmap';
@map("作业批阅",'teas.homeworkapprova','HomeWorkApprova')

export class HomeWorkApprova extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = ControlEditor;
        this._minute = '';
        this._id = null;
        this._idx = 0;
        this._data = null;
        this._isPre = true; //上一篇
        this._isLast = false;
        this._scale = 0;
        this._scaleCount = 0;
    }

    initTemplate() {
        return dom(this);
    }

    initEvent() {
    }

    createElement() {
        super.createElement();
        this.$iframe = this._handlers['iframe'];
    }

    renderContext() {
        let _this = this;
        if (!_this._root._isDesign) {
            super.renderContext();
            layui.form.render("select");
            _this.getHomeWorkApprovaData();
            _this.$markingSituation = _this._handlers['markingSituation'];
            _this.$progress = _this._handlers['progress'];
            _this.$isRemind = _this._handlers['isRemind'];
            _this.$prePage = _this._handlers['prePage'];
            _this.$nextPage = _this._handlers['nextPage'];
            _this.$prePage.on('click', function () {
                _this._isPre = true;
                _this.saveHomeWorkCorrect();
            })
            _this.$nextPage.on('click', function () {
                _this._isPre = false;
                _this.saveHomeWorkCorrect();
            })
            _this._handlers['zoomOut'].on('click', function () {
                --_this._scaleCount;
                if (_this._scaleCount < 0) {
                    _this._scaleCount = 0;
                }
                _this._scale = 1 + _this._scaleCount * 10 / 100;
                _this._handlers['iframe'].css("transform", "scale(" + _this._scale + ")")
            })
            _this._handlers['zoomIn'].on('click', function () {
                ++_this._scaleCount;
                _this._scale = 1 + _this._scaleCount * 10 / 100;
                _this._handlers['iframe'].css("transform", "scale(" + _this._scale + ")")
            })
            _this._timer = setInterval(function () {
                ++_this._minute;
                if (_this._minute > 20 * 1000 * 60) {
                    clearInterval(_this._timer);
                    _this.$isRemind.fadeIn();
                }
            }, 1000);
            _this._handlers['wrap'].css('height', window.innerHeight);
        }
    }

    renderReady() {
        super.renderReady();
    }

    getHomeWorkApprovaData(isreload) {
        // zyid=4a1abdada5494276bd2ec2e425cfb814
        // xyid=e08f405d848b4636a5dcd9812b3c4e88
        //?zyid=4a1abdada5494276bd2ec2e425cfb814&xyid=e08f405d848b4636a5dcd9812b3c4e88
        let _this = this;
        _this.zyid = dsf.url.queryString('zyid');
        _this.xyid = dsf.url.queryString('xyid') || '';
        let loadding = dsf.layer.loadding();
        let url = UrlSetting.getHomeWorkMarking;
        dsf.http.request(url, {zyglId: _this.zyid}, "GET")
            .done(function (res) {
                if (res.success) {
                    _this._data = res.data;
                    console.log(_this._data)
                    if (_this._data.list.length > 0) {
                        if (res.data['teas_jwgl_zygl.pgfs']['value'] == 1) {//1 等级制 2分数制
                            _this._handlers['isSelect'].show();
                            _this._handlers['isInput'].hide();
                        } else {
                            _this._handlers['isSelect'].hide();
                            _this._handlers['isInput'].show();
                        }
                        let _total = _this._data.list.length;
                        let _willMrking = _this._data.inCorrection;//未批阅数量
                        let _isMarked = (_total - _willMrking) + '/' + _total;//已批阅数量
                        let _progress = parseInt(((_total - _willMrking) / _total) * 100);
                        if (_progress == 0) {
                            _this.$progress.find('span').fadeOut();
                        } else {
                            _this.$progress.find('span').fadeIn().html(_progress + '%');
                        }
                        _this.$markingSituation.html(_isMarked);
                        _this.$progress.css('width', _progress + '%');
                        if (isreload) {//最后一条数据时 用户选择取消 重新加载数据
                            _this._idx = 0;
                            _this._id = _this._data.list[0].teas_jwgl_zygl_zyfbxy_id;
                            _this.regetval();
                            _this.previewfun(_this._data.list[0].zyfjid);
                            _this._isLast = false;
                        } else {
                            if (_willMrking > 0) {
                                if (_this.xyid) {//有学员的id 优先显示当前id数据  ???排序
                                    console.log('学员ID===>', _this.xyid);
                                    let _isleft = [];
                                    let _isright = [];
                                    for (let i = 0; i < _this._data.list.length; ++i) {
                                        if (_this._data.list[i].zyqjzt_value == 4) {
                                            _isleft.push(_this._data.list[i]);
                                        } else {
                                            _isright.push(_this._data.list[i]);
                                        }
                                    }
                                    if (_isleft.length > 0) {
                                        let _idx = null;
                                        for (let i = 0; i < _isleft.length; ++i) {
                                            if (_isleft[i].xsxx_value == _this.xyid) {
                                                let _str = _isleft[i];
                                                _isleft.splice(i, 1);
                                                _isleft.push(_str);
                                                break;
                                            }
                                        }
                                    }
                                    if (_isright.length > 0) {
                                        let _idx = null;
                                        for (let i = 0; i < _isright.length; ++i) {
                                            if (_isright[i].xsxx_value == _this.xyid) {
                                                let _str = _isright[i];
                                                _isright.splice(i, 1);
                                                _isright.unshift(_str);
                                                break;
                                            }
                                        }
                                    }
                                    _this._data.list = _isleft.concat(_isright);
                                    //let _temp = null;
                                    for (let i = 0; i < _this._data.list.length; ++i) {
                                        if (_this._data.list[i].xsxx_value == _this.xyid) {
                                            //_temp = _this._data.list[i];
                                            let preId = _this._data.list[i].zyfjid;//预览id
                                            _this.previewfun(preId);
                                            _this._idx = i;//索引
                                            _this._id = _this._data.list[i].teas_jwgl_zygl_zyfbxy_id;
                                            _this.regetval();
                                            break;
                                        }
                                    }
                                } else {
                                    for (let i = 0; i < _this._data.list.length; ++i) {
                                        if (_this._data.list[i].zyqjzt_value == 3) {
                                            let preId = _this._data.list[i].zyfjid;//预览id
                                            _this.previewfun(preId);
                                            _this._idx = i;//索引
                                            _this._id = _this._data.list[i].teas_jwgl_zygl_zyfbxy_id;
                                            break;
                                        }
                                    }
                                }
                            } else {
                                if (_this.xyid) {
                                    let _temp = null;
                                    for (let i = 0; i < _this._data.list.length; ++i) {
                                        if (_this._data.list[i].xsxx_value == _this.xyid) {
                                            _temp = _this._data.list[i];
                                            _this._data.list[i] = _this._data.list[0];
                                            _this._data.list[0] = _temp;
                                            _this.previewfun(_this._data.list[0].zyfjid);
                                            _this._idx = 0;//索引
                                            _this._id = _this._data.list[0].teas_jwgl_zygl_zyfbxy_id;
                                            _this.regetval();
                                            break;
                                        }
                                    }
                                } else {
                                    _this._idx = _this._data.list.length - 1;
                                    _this._id = _this._data.list[_this._idx].teas_jwgl_zygl_zyfbxy_id;
                                    _this.$markingSituation.html(_this._data.list.length + '/' + _this._data.list.length);
                                    _this.regetval();
                                    _this.previewfun(_this._data.list[_this._idx].zyfjid);
                                }
                            }
                        }
                    }
                } else {
                    dsf.layer.message('暂无数据');
                }
            })
            .error(function (err) {
                dsf.layer.message(err.message);
            })
            .always(function () {
                dsf.layer.close(loadding);
            }).exec();
    }

    saveHomeWorkCorrect() {
        let _this = this;
        if (!_this._data || _this._data.list.length == 0) return;
        _this.$achievement = _this._handlers['achievement'].find("option:selected").text();
        _this.$achieveFs = _this._handlers['achieveFs'].val();
        _this.$comment = _this._handlers['comments'].val();
        let params = {
            py: _this.$comment,//评语
            cj_value: _this.$achievement == '优秀' ? '1' : _this.$achievement == '良好' ? '2' : _this.$achievement == '一般' ? '3' : '4',//成绩_文本
            cj_text: _this.$achievement,//成绩_值
            zyfbxyId: _this._id, //作业id
            cjfs: _this.$achieveFs
        }
        _this._data.list[_this._idx].py = params.py;
        _this._data.list[_this._idx].cj_value = params.cj_value;
        if (_this._data['teas_jwgl_zygl.pgfs']['value'] == 1) {
            _this._data.list[_this._idx].cj_text = params.cj_text;
        } else {
            _this._data.list[_this._idx].cjfs = params.cjfs;
        }
        if (_this._isPre) {
            --_this._idx;
            if (_this._idx < 0) {
                dsf.layer.message('没有更多作业了.');
                _this._idx = 0;
                return;
            }
            _this.regetval();
            _this.previewfun(_this._data.list[_this._idx].zyfjid);
            return;
        } else {
            if (_this._data['teas_jwgl_zygl.pgfs']['value'] !== '1') {
                if (params.cjfs == '') {
                    dsf.layer.message('成绩分数不能为空');
                    return;
                } else if (params.cjfs > 100 || params.cjfs < 0) {
                    dsf.layer.message('成绩分数只能是0-100');
                    return;
                }
            }
            ++_this._idx;
            if (_this._idx > _this._data.list.length - 1) {
                _this._idx = _this._data.list.length - 1;
                _this._isLast = true;
                dsf.layer.confirm("作业已全部批阅，是否完成提交并关闭页面?", () => {
                    //最后一条数据时提交单独调用新的接口
                    _this.submitComment(params);
                }, () => {
                    _this._isLast = false;
                    _this.getHomeWorkApprovaData(true);
                })
            } else {
                _this.submitComment(params);
            }
        }
    }

    submitComment(params) {
        let _this = this;
        let url = UrlSetting.saveHomeWorkCorrect;
        let loadding = dsf.layer.loadding();
        dsf.http.request(url, params, "POST")
            .done(function (res) {
                if (res.success) {
                    if (_this._data.list.length > 1) {
                        if (_this._data.list[_this._idx - 1].zyqjzt_value == 3) {
                            _this.renderProgress();
                            _this._data.list[_this._idx - 1].zyqjzt_value = 4;
                        }
                    }
                    if (_this._isLast) {//最后一条数据提交成功
                        let params = {
                            zyglId: dsf.url.queryString('zyid')
                        };
                        _this.lastCommentSubmit(params);
                    }
                    _this.regetval();
                    _this.previewfun(_this._data.list[_this._idx].zyfjid);//预览文件id
                } else {
                    _this._idx = _this._idx - 1;
                    dsf.layer.message(res.message);
                }
                window.opener.page.event.trigger(PageEvent.READY);
            })
            .error(function (err) {
                dsf.layer.message(err.message);
            })
            .always(function () {
                dsf.layer.close(loadding);
            }).exec();
    }

    lastCommentSubmit(params) {
        let _this = this;
        let url = UrlSetting.saveAllHomeworkCorrect;
        let loadding = dsf.layer.loadding();
        dsf.http.request(url, params, "POST")
            .done(function (res) {
                if (res.success) {
                    _this._isLast = false;
                    dsf.layer.message('作业全部批阅成功');
                    // window.opener.page.event.trigger(PageEvent.READY);
                    window.close();
                } else {
                    dsf.layer.message(res.message);
                }
            })
            .error(function (err) {
                dsf.layer.message(err.message);
            })
            .always(function () {
                dsf.layer.close(loadding);
            }).exec();
    }

    previewfun(id) {
        if (id == '' || id == null) {
            this.$iframe.contents().find('body').html("<img style='transform: translateY(-50%);position: relative;top: 50%' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>").css({'text-align': 'center'});
            return;
        }
        let previewUrl = dsf.url.getWebPath('preview/file?fileId=' + id);
        this.$iframe.attr('src', previewUrl);
    }

    regetval() {
        let _this = this;
        let _cjval = this._data.list[this._idx].cj_value || 1;
        let _cjfs = this._data.list[this._idx].cjfs || '';
        let _comsg = this._data.list[this._idx].py || '';
        _this._id = this._data.list[_this._idx].teas_jwgl_zygl_zyfbxy_id;
        if (_this._data['teas_jwgl_zygl.pgfs']['value'] == '1') {
            _this._handlers['achievement'].val(_cjval);
            layui.form.render('select')
        } else {
            _this._handlers['achieveFs'].val(_cjfs);
        }
        _this._handlers['comments'].val(_comsg);
    }

    renderProgress() {
        if (this._data.inCorrection !== 0) {
            if (this._isPre) {
                ++this._data.inCorrection;
                if (this._data.inCorrection > this._data.list.length) {
                    this._data.inCorrection = this._data.list.length;
                }
            } else {
                --this._data.inCorrection;
                if (this._data.inCorrection < 0) {
                    this._data.inCorrection = 0;
                }
            }
            let _progress = parseInt((this._data.list.length - this._data.inCorrection) / this._data.list.length * 100);
            if (_progress == 0) {
                this.$progress.find('span').fadeOut();
            } else {
                this.$progress.find('span').fadeIn().html(_progress + '%');
            }
            this.$progress.css('width', _progress + '%');
            let _isAll = null;
            if (this._isLast) {
                _isAll = this._idx + 1;
            } else {
                _isAll = this._idx;
            }
            this.$markingSituation.html(_isAll + '/' + this._data.list.length);
        }
    }
}