import dom from '../templates/CurClass.ejs';
import {ControlEditor} from "../../../editor/ControlEditor";
import {UrlSetting} from "../../../core/pageAction";

import {map} from '../../../decorator/controlmap';
@map("当前班级",'teas.curclass','CurClass')

export class CurClass extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = ControlEditor;
        this.moreHref = dsf.url.getWebPath('teas/jwgl/bjgl/views/nowlistbc.html');
    }

    initTemplate() {
        return dom(this);
    }

    initEvent() {

    }

    createElement() {
        super.createElement();
    }

    renderContext() {
        super.renderContext();
        if (!this._root._isDesign) {
            let _this = this;
            _this.getCurClassData();
        }
    }

    renderComplete() {
        super.renderComplete();
    }

    getCurClassData() {
        let _this = this;
        let loadding = dsf.layer.loadding();
        let url = UrlSetting.getCurClassInfo;
        let params = {
            currentPage: 1,
            pageSize: 3,
        }
        dsf.http.request(url, params, "GET")
            .done(function (res) {
                if (res.success) {
                    console.log(res)
                    if (res.data.list.length > 0) {
                        _this._handlers['total'].html(res.data.totalRow);
                        _this.renderPage(res.data.list);
                    } else {
                        _this._handlers['total'].html(0);
                        _this._handlers['curclassInfo'].html("<img style=';position: relative;top: 28px' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>").css({'text-align': 'center'})
                    }
                } else {
                    dsf.layer.message();
                }
            })
            .error(function (err) {
                dsf.layer.message();
                console.log(err)
            })
            .always(function () {
                dsf.layer.close(loadding);
            }).exec();
    }

    renderPage(data) {
        let _str = "";
        let _nowDate = new Date();
        _nowDate = _nowDate.getTime();
        for (let i = 0; i < data.length; ++i) {
            let _beginDate = data[i].pxsj_sdate;
            let _endDate = data[i].pxsj_edate;
            let _progreeIng = parseInt(((_nowDate - (new Date(_beginDate).getTime())) / ((new Date(_endDate).getTime()) - (new Date(_beginDate).getTime()))) * 100);
            _str += "         <li>" +
                "                <h3 class='til'>" + data[i].NAME + "</h3>" +
                "                <div class='wrap'>" +
                "                    <span class='datepre'>" + dsf.date.format(_beginDate, 'mm-dd') + "</span>" +
                "                    <div class='progress'>" +
                "                        <div class='inner' style='width:" + _progreeIng + "%'></div>" +
                "                    </div>" +
                "                    <span class='datenext'>" + dsf.date.format(_endDate, 'mm-dd') + "</span>" +
                "                </div>" +
                "            </li>"
        }
        this._handlers['curclassInfo'].html(_str);
    }
}