import dom from '../templates/WeekCourseTable_hw.ejs';
import { ControlEditor } from '../../../editor/ControlEditor';
import { relyFiles } from '../../../core/relyfiles';
import { Action, UrlSetting } from '../../../core/pageAction';
import { PageEvent } from '../../../core/ControlEvent';
import {map} from '../../../decorator/controlmap';

let temp2 = {
    "上午": "1",
    "下午": "2",
    "晚上": "3"
}


@map("一周课表",'teas.weekcoursetable','WeekCourseTable')
@relyFiles([
    'res/libs/jquery-ui/jquery-ui.min.css',
    'res/libs/jquery-ui/jquery-ui.min.js'
])
export class WeekCourseTable extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = ControlEditor;
        this._year = (new Date()).getFullYear();
        this._month = (new Date()).getMonth();
        this._day = (new Date()).getDate();
        this._week = null;
        this._yearOld = null;
        this._monthOld = null;
        this._classData = null;
        this._periods = ["上午", "下午", "晚上"];
		this._isShowRole = false
        // 是否查询所有班级
        this.queryType = true;
        // 班级ID
        this._classId = dsf.url.queryString("classid");
        // 支部ID
        this._branchId = dsf.url.queryString("branchid");
    }
    set year(value) {
        this._year = value;
    }
    get year() {
        return this._year;
    }

    set month(value) {
        this._month = value;
    }
    get month() {
        return this._month;
    }

    set day(value) {
        this._day = value;
    }
    get day() {
        return this._day;
    }

    initTemplate() {
        return dom(this);
    }
    render() {
        let _this = this;
        super.render();

        //年月日选择器
        layui.laydate.render({
            "elem": '#date',
            "format": "yyyy年MM月dd日",
            "btns": ['now', 'confirm'],
            "value": getCurrentMonth.call(this),
            "done": (value, date, endDate) => {
                _this.year = parseInt(date.year);
                _this.month = parseInt(date.month) - 1;
                _this.day = parseInt(date.date);
                this.renderSchedule();
            }
        });

        if (!_this.root._isDesign) {
            _this.root.event.on(PageEvent.READY, evt => {
                _this.renderSchedule();
            });
        } else {
            _this.renderSchedule();
        }

        this._handlers.upWeek.on("click", evt => {
            _this.changeWeek(true);
        })
        this._handlers.nextWeek.on("click", evt => {
            _this.changeWeek(false);
        })
        this._handlers.exportCT.on("click", evt => {
            // 导出
            let calendar = dsf.date.getMonthWeekDate(_this.year, _this.month, _this.day).list;

            let url = dsf.url.getWebPath("teas/yzkb/exportClassSchedule");
            $('<form action="' + url + '" method="get">' + // action请求路径及推送方法
                '<input type="text" name="sksj_sdate" value="' + dsf.date.format(calendar[0].date, 'yyyy-mm-dd') + '"/>' + 
                '<input type="text" name="sksj_edate" value="' + dsf.date.format(calendar[6].date, 'yyyy-mm-dd') + '"/>' + 
                '<input type="text" name="queryType" value="' + ( _this.queryType ? 1 : 0) + '"/>' + 
                '<input type="text" name="classId" value="' + _this._classId + '"/>' + 
                '<input type="text" name="branchId" value="' + _this._branchId + '"/>' + 

                '</form>')
            .appendTo('body').submit().remove();
        })

    }
    renderSchedule() {
        let _this = this;
        let listObj = dsf.date.getMonthWeekDate(this.year, this.month, this.day);
        if (listObj.week == _this._week && listObj.year == _this._yearOld && listObj.month == _this._monthOld) {
            return;
        }
        _this._week = listObj.week;
        _this._yearOld = listObj.year;
        _this._monthOld = listObj.month;
        let list = listObj.list;

        this._handlers.schedule_wrap.html("");

        // 一周表头
        for (let i = 0; i < list.length; i++) {
            let row = list[i];
            this._handlers["weekday" + (i + 1)].find('.ds_day_text').html((row.date.getMonth() + 1) + "/" + row.date.getDate());
        }
        _this._handlers.className.html("一周课表(" + (list[0].date.getMonth() + 1) + "月" + (list[0].date.getDate()) + "日—" + (list[6].date.getMonth() + 1) + "月" + (list[6].date.getDate()) + "日)");

        if (!_this.root._isDesign) {
            loadData.call(this, list, () => {
                if (_this._classData && _this._classData.length > 0) {
                    for (let i = 0; i < _this._classData.length; i++) {
                        let div = $("<div class='ds_schedule_content'>");
                        let table = $("<table class='table'>").appendTo(div);
                        let tbody = $("<tbody>").appendTo(table);
                        let classData = _this._classData[i];
                        // 整理课程
                        if (classData.courseInfo && classData.courseInfo.length > 0) {
                            let course = classData.courseInfo;
                            let temp = {};
                            for (let c = 0; c < course.length; c++) {
                                let d = course[c];
                                let rq = d["skrq"];
                                let wb = d["wb_text"];
                                if (!temp[rq]) {
                                    temp[rq] = {
                                        "上午": [],
                                        "下午": [],
                                        "晚上": []
                                    };
                                }
                                let stime = dsf.date.format(d["sksj_sdate"], 'hh:ii');
                                let etime = dsf.date.format(d["sksj_edate"], 'hh:ii');
                                let kcdata = {
                                    "_type": "kc",
                                    "id": d["teas_jwgl_pkgl_id"],
                                    "kc": d["kc_text"],
                                    "jxxs": d["jxxs"],
                                    "skjs": d["skjs_text"],
                                    "skdd": d["skdd_text"],
                                    "stime": stime,
                                    "etime": etime,
                                    "isIkt": d["icourse_text"] == "1" || false,
                                    "istk": d["istk_value"] == "1" || false
                                }
                                temp[rq][wb].push(kcdata);
                            }
                            classData.courseInfo = temp;
                        } else {
                            classData.courseInfo = {};
                        }
                        // 填充内容
                        let wspk = classData["hasNight"] ? classData["hasNight"] : 0;
                        for (let n = 0; n < dsf.teas.periods.length; n++) {
                            let tr = $("<tr>");
                            for (let j = 0; j < list.length; j++) {
                                let row = list[j];
                                if (j == 0) {
                                    if (n == 0) {
                                        let classname = $("<td class='ds_classname' rowspan='" + (wspk == 1 ? 3 : 2) + "'><div>" + classData.bjname + "</div></td>")
                                        tr.append(classname);
                                    }
                                    let period = $("<td class='ds_period'><div>" + dsf.teas.periods[n] + "</div></td>");
                                    tr.append(period);
                                }
                                let td = $("<td></td>");
                                $("<div class='ds_day ds_day_content' d='" + (dsf.date.format(row.date, 'yyyy-mm-dd')) + "' period='" + dsf.teas.periods[n] + "'></div>").appendTo(td);
                                tr.append(td);
                            }
                            if (dsf.teas.periods[n] == '晚上' && wspk == 0) {
                                tr.hide();
                            }
                            tbody.append(tr);
                            for (let k in classData.courseInfo) {
                                let isMore = classData.courseInfo[k][dsf.teas.periods[n]].length > 1 ? true : false;
                                for (let y in classData.courseInfo[k][dsf.teas.periods[n]]) {
                                    let td_course = tr.find(".ds_day[d='" + k + "']");
                                    if (td_course.length > 0) {
                                        addToTable.call(_this, classData.courseInfo[k][dsf.teas.periods[n]][y], td_course, isMore)
                                    }
                                }
                            }
                        }
                        this._handlers.schedule_wrap.append(div);
                    }
                } else {
                    let div = $("<div class='ds_schedule_content noData'>");
                    $("<img src='/dsfa/res/dsf_styles/themes/img/nodata.png'>").appendTo(div);
                    this._handlers.schedule_wrap.html(div)
                }
                this.resize();
            });
        } else {
            this.resize();
        }
    }

    resize() {
        if (this.element) {
            let w = this._handlers.box.width();
            this._handlers.header.css("width", w);
            this._handlers.content.css("width", w);
            setCellSize.call(this);
        }
        super.resize();
    }

    initEvent() {

    }

    changeWeek(isUp) {
        // 上一周/下一周
        let date = null;
        if (isUp) {
            date = dsf.date.getBeforDate(this.year, this.month, this.day);
        } else {
            date = dsf.date.getAfterDate(this.year, this.month, this.day);
        }
        this._year = date.getFullYear();
        this._month = date.getMonth();
        this._day = date.getDate();
        this._handlers.date.html(dsf.date.format(date, "yyyy年mm月dd日"))
        this.renderSchedule();
    }
}

function setCellSize() {
    let period_width = 45;
    let classname_width = 170;
    //计算表格宽度
    let schedule_width = this._handlers.schedule.width();
    this._handlers.weekday.css("width", schedule_width);
    let cell_width = (schedule_width - period_width - classname_width) / 7;
    this._handlers.right.find(".ds_day").width(cell_width - 2);
}

function getCurrentMonth(format) {
    let d = new Date(this.year, this.month, this.day);
    format = format || "yyyy年mm月dd日";
    let v = dsf.date.format(d, format);
    return v;
}

function loadData(calendar, callback) {
    let layerIndex = dsf.layer.loadding();
    let _this = this;
    let data = {
        "sksj_sdate": dsf.date.format(calendar[0].date, 'yyyy-mm-dd'),
        "sksj_edate": dsf.date.format(calendar[6].date, 'yyyy-mm-dd'),
        "queryType": _this.queryType ? 1 : 0,
        "classId": _this._classId,
        "branchId":_this._branchId
    }
    let url = UrlSetting.getWeekCourseTable;
    dsf.http.request(url, data, "GET")
        .done(response => {
            if (response.success) {
                _this._classData = response.data;
                console.log(response.data);
                callback();
            } else {
                dsf.layer.message(dsf.prompt.loaddatafail, false);
            }
        })
        .error(response => {
            dsf.layer.message(dsf.prompt.loaddatafail, false);
        })
        .always(function () {
            dsf.layer.close(layerIndex);
        })
        .exec();
}

function addToTable(data, box, more) {
    let div = $("<div class='ds_class_item " + (more ? "ds_more " : "") + (data.isIkt ? "ikt " : "") + (data.istk ? "adjust" : "") + "' data-id='" + data.id + "'>" +
        "<div class='ds_class_time'>" + data.stime + "至" + data.etime + "</div>" +
        "<div class='ds_class_type'>" + (data.jxxs || '') + "</div>" +
        "<div class='ds_class'>" + (data.kc || '') + "</div>" +
        "<div class='ds_class_jsname'>" + (data.skjs || '').split('^').join('、') + "</div>" +
        "<div class='ds_class_address'>" + (data.skdd || "未安排").split('^').join('、') + "</div>" +
        "</div>");
    box.append(div);

    if(dsf.url.queryString("showCourseDes")=='1'){
        div.on("click", openDes.bind(this, data));
    }

    function openDes(data) {
        // teas_jwgl_pkgl_id 能拿到课程id,班级id
        // window.open(dsf.url.getWebPath("teas/xyxt/kcap/views/kcjs.html?id=" + data.id));
        dsf.layer.openDialog({
            title: "课程介绍",
            content: dsf.url.getWebPath("teas/xyxt/kcap/views/kcjs.html?id=" + data.id),
            area: ['900px', '550px']
        });
    }
}

