import dom from '../templates/TableSelector.ejs';
import { map } from '../../../decorator/controlmap';
import { isSupportDataPost } from "../../../core/postDecorator";
@map('表格树选择', 'teas.tableselector', 'TableSelector')
@isSupportDataPost(true)

export class TableSelector extends dsf.Controls.LayoutControl {
  constructor(id, isPart) {
    super(id, isPart);
    this._value = [];
    // 数量上限
    this.maxLength = null;

    // 接口值
    this.sqlUrl = null;
    // 选择的元数据
    this.chooseMetaData = {};
    this.choosenLimit = 15;
    this.showField = 'name';
    this.uniqueField = 'id';
    // 启用tab
    this.useTab = false;
    // tab配置
    this.tabOpts = [];
    this.defaultOpts = this.getDefaultOpts('default');
    this._activeId = 'default';
    this._choosenPage = 1;
    this._searchText = '';
    this._currPageTempData = [];
    this._breadcrumbList = [];
  }

  set _showField(v) {
    this.showField = v;
  }

  get _showField () {
    return this.showField || 'name';
  }

  set _uniqueField(v) {
    this.uniqueField = v;
  }

  get _uniqueField () {
    return this.uniqueField || 'id';
  }  

  set _choosenLimit(v) {
    this.choosenLimit = v;
  }

  get _choosenLimit () {
    return this.choosenLimit;
  }  

  set _useTab(v) {
    this.useTab = v;
    this.render();
  }

  get _useTab() {
    return this.useTab;
  }

  get _options() {
    return [this._defaultOpts, ...this._tabOpts];
  }

  get _activeOption() {
    return this._options.find(it => it.id === this._activeId);
  }

  get _activeBreadcrumb() {
    const obj = this._breadcrumbList.find(it => it.id === this._activeId);
    return obj ? obj.items || [] : [];
  }

  set _activeBreadcrumb(v) {
    const obj = this._breadcrumbList.find(it => it.id === this._activeId);
    if (obj) {
      obj.items = v;
    }
    this.renderBreadcrumb();
  }  

  set value(v) {
    // 设置选中值
    this._value = v;
    this.updateChooseLength();
    this.renderChoosenPage();
    this.renderChoosenList();    
  }
  get value() {
    return this._value;
  }

  set _maxLength(v) {
    //设置数量上限
    this.maxLength = parseInt(v) || 0;
  }
  get _maxLength() {
    return this.maxLength || 0;
  }

  get _defaultOpts() {
    return this.defaultOpts;
  }

  set _defaultOpts(v) {
    this.defaultOpts = v;
  }

  set _tabOpts(v) {
    this.tabOpts = v;
  }

  get _tabOpts() {
    return this.tabOpts;
  }

  getDefaultOpts(id) {
      const defaultOpts = this._defaultOpts || {};
      const obj = $.extend(true, {
        cols: [],
        url: '',
        name: '',
        loading: false,
        request: {
          pageName: 'pageNum',
          limitName: 'pageSize'
        },
        isTree: true,
        responseField: {
          msg: 'message',
          count: 'dataCount',
          data: 'data'
        },
        page: {
          count: 0,
          limit: 15,
          limits: [15,25,30,40,50,100],
          curr: 1,
          groups: 5,
          layout: ['prev','page','next','count','skip','limit'],
          prev: "<i class='iconfont icon-left'></i>",
          next: "<i class='iconfont icon-right'></i>",  
          theme: '#cd0911',            
        }          
      }, defaultOpts, { id });
      return obj;
  }

  initTemplate() {
    return dom(this);
  }

  renderEvent() {
    this._handlers.chooseList.on('click', '.closeIcon', (ev) => {
      const id = $(ev.target).parent('.item').data('id');
      const index = this.value.findIndex(it => it[this.uniqueField] === id);
      const data = [...this.value];
      data.splice(index, 1);
      this.value = data;
    });
    this._handlers.empty.on('click', () => {
      this.value = [];
    });
    this._handlers['layui-tab-title'].on('click', '.tab-pane', (ev) => {
      const target = $(ev.target || ev.srcElement);
      const id = target.attr('handler').replace('tab-pane-', '');
      this._activeId = id;
      this.renderTable();
    });
    this._handlers.search_input.on('input', (ev) => {
      this._searchText = ev.target.value;
    });
    this._handlers.search_clear.on('click', (ev) => {
      this._searchText = '';
      this._handlers.search_input.val('');
      layui.table.reload(this._activeId);
    });
    this._handlers.search.on('click', (ev) => {
      const query = this._handlers.search_input.val();
      layui.table.reload(this._activeId, {
        where: {
          query,
        }
      });
    });
    this._handlers.breadcrumb.on('click', 'a[data-id]', (ev) => {
      const id = $(ev.target).data('id');
      const index = parseInt($(ev.target).data('index'), 10);
      const temp = [...this._activeBreadcrumb];
      this._activeBreadcrumb = temp.slice(0, index - 1);
      layui.table.reload(this._activeId, {
        where: {
          id,
        }
      });      
    });
    layui.table.on(`checkbox(${this.id}_table)`, (obj) => {
      const { checked, data, type, tr } = obj;
      let temp = [...this.value];
      if (type === 'one') {
        if (checked) {
          if (!this._maxLength || this.value.length < this._maxLength) {
            temp.push(data);
          } else {
            $(tr).find('input[type=checkbox]').prop('checked', false);
            layui.form.render('checkbox');
            layer.msg(`最多选择${this._maxLength}条`);
          }
        } else {
          const index = temp.findIndex(it => it[this._uniqueField] === data[this._uniqueField]);
          index !== -1 && temp.splice(index, 1);
        }
      } else {
        if (checked) {
          const newData = this._currPageTempData.filter(it => {
            return !temp.some(item => it[this._uniqueField] === item[this._uniqueField]);
          });
          temp = temp.concat(newData);
        } else {
          const ids = this._currPageTempData.map(it => it[this._uniqueField]);
          temp = temp.filter(it => !ids.includes(it[this._uniqueField]));
        }
      }
      this.value = temp;
    });
    layui.table.on(`rowDouble(${this.id}_table)`, ({ data }) => {
      if(this._activeOption.isTree) {
        layui.table.reload(this._activeId, {
          where: {
            id: data[this._uniqueField],
          }
        });        
      }      
    });      
  }
  changeUseTab() {
    this._handlers['tab'].toggle(this.useTab);
  }
  renderReady() {
    super.renderReady();
    this.renderEvent();
    this.changeUseTab();
    this.renderChoosenList();
    this.renderChoosenPage();
    this.root.event.on(PageEvent.READY, evt => {
        this.renders();
    });
  }
  renders() {
    if (this.useTab) {
        const fn = () => {
            let tabTitles = '';
            this._tabOpts.forEach((tab, index) => {
              const handler = `tab-pane-${tab.id}`;
              tabTitles += `<li class="tab-pane" handler="${handler}">${tab.name}</li>`;
            });
            this._handlers['layui-tab-title'].empty();
            this._handlers['layui-tab-title'].append(tabTitles);
            this._handlers['layui-tab-title'].find('.tab-pane:eq(0)').trigger('click');
          }
          if (this.root._isDesign) {
            fn();
          }
          this.root.event.on(PageEvent.READY, evt => {
            fn();
          })
    } else {
        this.renderTable();
    }
  }
  getValueByContext(ctx, key = '') {
    const str = key.replace(/\s/g, '').split('.');
    return str.reduce((a, b) => {
      return a[b];
    }, ctx);
  }
  renderTable() {
    const _this = this;
    const tableOption = {
        elem: `#${this.id}_table`,
        height: 'auto',
        where: {
          pageName: _this.root.$name,
          namespace: _this.root.nameSpace,          
        },
        parseData: (d) => {
          const { responseField } = _this._activeOption;
          const { msg, count, data } = responseField || {};
          const message = _this.getValueByContext(d, msg);
          let items = _this.getValueByContext(d, data);
          const dataCount = _this.getValueByContext(d, count);
          if (d.success) {
            const checkedIds = _this.value.map(it => it[_this._uniqueField]);
            items = items.map(it => {
              const LAY_CHECKED = checkedIds.includes(it[_this._uniqueField]);
              it.LAY_CHECKED = LAY_CHECKED;
              return it;
            });
            return {
              code: 0,
              msg: message,
              count: dataCount,
              data: items,
            }
          } else {
            return {
              code: 0,
              msg: message,
              count: 0,
              data: []
            }
          }
        },        
        done(res, curr, count) {
          _this._activeOption.page.curr = curr;
          _this._activeOption.page.count = count;
          _this._currPageTempData = res.data;
          const reduceData = _this._currPageTempData.filter(it => !_this.value.some(it2 => it[_this._uniqueField] === it2[_this._uniqueField]));
          if (_this._maxLength && _this.value.length + reduceData.length > _this._maxLength) {
            $(`[lay-id=${_this._activeId}] thead input[type=checkbox]`).prop('disabled', true);
            layui.form.render('checkbox');
          }
        }
    };
    let cols = $.extend(true, [], this._activeOption.cols);
    cols = cols.map(it => {
      const obj = $.extend(true, {}, it);
      if (obj.templet) {
        obj.templet = `<div>${obj.templet}</div>`;
      }
      return obj;
    });    
    $.extend(true, tableOption, this._activeOption, {
      url: dsf.url.getWebPath(tableOption.url),      
    });
    tableOption.cols = [[{type: 'checkbox'}, ...cols]];
    layui.table.render(tableOption);
    this.renderBreadcrumb();
  }
  renderBreadcrumb() {  
    this._handlers['breadcrumb'].empty();
    if (this._activeBreadcrumb.length && this._activeOption.isTree) {
      const fragment = document.createDocumentFragment();
      const home = {};
      home[this._uniqueField] = '';
      home[this._showField] = '首页';
      const arr = [ home, ...this._activeBreadcrumb];
      arr.forEach((node,i) => {
        const li = document.createElement('a');
        li.setAttribute('href', 'javascript:;');
        if (i === arr.length - 1) {
          li.innerHTML = `<cite>${node[this._showField]}</cite>`;
        } else {
          li.innerHTML = `${node[this._showField]}`;
          li.setAttribute('data-id', node[this._uniqueField]);
          li.setAttribute('data-index', i);
        }
        fragment.appendChild(li);
      });
      this._handlers['breadcrumb'].append(fragment);    
      layui.element.render('breadcrumb', 'breadcrumb');
    }
  }
  updateChooseLength() {
    this._handlers['chooseLength'].text(this._value.length);
  }
  renderChoosenPage() {
    if (this._value.length < this._choosenLimit) {
      this._handlers.page.hide();
    } else {
      this._handlers.page.show();
      layui.laypage.render({
        elem: this._handlers.page,
        count: this._value.length,
        theme: '#cd0911',
        curr: this._choosenPage,
        limit: this._choosenLimit,
        jump: ({ curr }) => {
          this._choosenPage = curr;
          this.renderChoosenList();
        }
      });
    }
  }
  renderChoosenList() {
    const arr = this.value.slice(this._choosenPage*this._choosenLimit - this._choosenLimit, this._choosenPage*this._choosenLimit);
    const fragment = document.createDocumentFragment();
    arr.forEach((node,i) => {
      const li = document.createElement('li');
      li.setAttribute('class', 'item');
      li.setAttribute('data-id', node[this._uniqueField]);
      li.innerHTML = `${node[this._showField]}<i class='closeIcon iconfont icon-guanbi1'></li>`;
      fragment.appendChild(li);
    });
    this._handlers['chooseList'].empty();
    this._handlers['chooseList'].append(fragment);
  }
}
