import dom from '../templates/YearClassStuation.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { UrlSetting } from "../../../core/pageAction";
import { relyFiles } from "../../../core/relyfiles";
import { map } from '../../../decorator/controlmap';

@map("年度办班情况", 'teas.yearclassstuation', 'YearClassStuation')
@relyFiles([
    'res/libs/echarts/echarts.min.js',
    'res/libs/jquery-ui/jquery-ui.min.js'
])
export class YearClassStuation extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = ControlEditor;
        this.childDept = [];
        this.color = ['#db853c', '#4099af', '#70588f', '#89a54e', '#ab4642', '#44727a', '#66D9EF', '#FF6F6F', '#D0D8DB'];//报表调色板
    }

    initTemplate() {
        return dom(this);
    }


    createElement() {
        super.createElement();
    }

    renderReady() {
        super.renderReady();
    }

    renderContext() {
        super.renderContext();
        let _this = this;
        let _year = new Date().getFullYear();
        let _yearStr = '';
        for (let i = 0; i < 4; i++) {
            _yearStr += "<option value='" + (_year - i) + "' data-val='" + (i + 1) + "'>" + (_year - i) + "年度</option>"
        }
        _this._handlers['yearSituation'].html(_yearStr);
        layui.form.render('select');
        if (!_this._root._isDesign) {
            _this.pageInit();
            _this._handlers['yearClassSituation'].css('min-width', '780px');
            layui.form.on('select(year)', function (data) {
                _this.params.year = data.value;
                _this.getClassSituationData();
            })
        }
    }

    renderComplete() {
        super.renderComplete();
    }

    pageInit() {
        let _this = this;
        _this.params = {
            year: _this._handlers['yearSituation'].find("option:selected").val()
        }
        this.getClassSituationData();
    }

    getClassSituationData() {
        let _this = this;
        let loadding = dsf.layer.loadding();
        let url = UrlSetting.getClassSituationEcharts;
        dsf.http.request(url, _this.params, "GET")
            .done(function (res) {
                console.log(res)
                if (res.success) {
                    _this.resData = res.data.list;

                    _this.renderClassInfo(res.data.countInfo);
                    if (res.data.list.length > 0) {
                        _this.renderEcharts();
                    }
                } else {
                    dsf.layer.message(res.message);
                }
            })
            .error(function (err) {
                dsf.layer.message();
                console.log(err)
            })
            .always(function () {
                dsf.layer.close(loadding);
            }).exec();
    }

    renderEcharts(params) {
        let _this = this,
            resData = _this.resData,
            color = _this.color.slice(0, resData.length),
            childDept = _this.childDept,
            echart = echarts.init(document.getElementById('formecharts'));
        _this.itemStyle = {
            emphasis: {
                barBorderWidth: 1,
                shadowBlur: 2,
                shadowOffsetX: 0,
                shadowOffsetY: 0,
                shadowColor: 'rgba(0,0,0,0.5)'
            }
        };
        let option = {
            tooltip: {
                trigger: 'axis',
                axisPointer: {
                    type: 'shadow'
                }
            },
            legend: {
                orient: 'vertical',
                data: _this.echartsLegend(),
                left: '3%',
                top: '15%'
            },
            // grid: {
            //     top: '10%',
            //     right: '5%',
            //     bottom: '28%'
            // },
            grid: {
                top: '10%',
                left: '25%',
                right: '4%',
                bottom: '3%',
                containLabel: true
            },
            color: color,
            xAxis: {
                type: 'category',
                data: _this.echartsXaxis(),
                axisLine: {
                    show: false,
                },
                axisTick: {
                    show: false
                },
                axisLabel: {
                    interval: 0,
                    formatter: function (value) {
                        let str = "";
                        let num = 3; //每行显示字数
                        let valLength = value.length; //该项x轴字数
                        let rowNum = Math.ceil(valLength / num); // 行数
                        if (rowNum > 1) {
                            for (let i = 0; i < rowNum; i++) {
                                let temp = "";
                                let start = i * num;
                                let end = start + num;
                                temp = value.substring(start, end) + "\n";
                                str += temp;
                            }
                            return str;
                        } else {
                            return value;
                        }
                    }
                }
            },
            yAxis: [
                {
                    type: 'value',
                    axisLine: {
                        lineStyle: {
                            color: '#e6e6e6',
                        }
                    },
                    axisTick: {
                        show: false
                    },
                    splitLine: {
                        lineStyle: {
                            color: '#e6e6e6',
                        }
                    }
                }
            ],
            series: this.echartsSeries()
        };
        echart.setOption(option);
        echart.on('click', function (params) {
            let _curDept = params.name;//
            let _childDept = params.seriesName;
            let _curChildIdx = params.seriesIndex;
            let bjlb_value = null;
            console.log(params)
            for (let i = 0; i < resData[0].datas.length; ++i) {
                if (resData[0].datas[i].bjlb_text == _curDept) {
                    bjlb_value = resData[0].datas[i].bjlb_value;
                    break;
                }
            }
            _this.getDeptDetailInfo(bjlb_value, _curDept, childDept[_curChildIdx], _childDept);
            echart.setOption(option);
        });
    }

    echartsLegend() {
        let data = this.resData;
        if (data.length > 0) {
            let legend = [];
            for (let i = 0; i < data.length; ++i) {
                legend.push(data[i].bclx_text)
            }
            return legend;
        }
    }

    echartsXaxis() {
        let data = this.resData;
        if (data[0].datas.length > 0) {
            let xaxis = [];
            for (let i = 0; i < data[0].datas.length; ++i) {
                xaxis.push(data[0].datas[i].bjlb_text);
            }
            return xaxis;
        }
    }

    echartsSeries() {
        let _this = this;
        let series = [];
        if (_this.resData.length > 0) {
            for (let i = 0; i < _this.resData.length; ++i) {
                _this.childDept.push(_this.resData[i].bclx_value)
                let item = _this.resData[i].datas;
                let data = [];
                for (let k = 0; k < item.length; k++) {
                    data.push(item[k].num);
                }
                series.push({
                    name: _this.resData[i].bclx_text,
                    type: 'bar',
                    barWidth: '25',
                    stack: '部门',
                    data: data,
                    itemStyle: _this.itemStyle
                })
            }
            return series;
        }
    }

    renderEchartItemStyle(name, idx, type) {
        let yArr = ['专题研讨类', '进修类', '培训类', '研修类', '师资类', '部门培训类', '测试'];
        let color = ['#db853c', '#4099af', '#70588f', '#89a54e', '#ab4642', '#44727a', '#333333'];
        let selectedColor = '#b40404';//选中颜色
        if (type == 0) {
            for (let i = 0; i < yArr.length; ++i) {
                if (name == yArr[i]) {
                    if (idx == i) {
                        return selectedColor;
                    } else {
                        return color[i];
                    }
                }
            }
        } else {
            for (let k = 0; k < yArr.length; ++k) {
                // if (name == yArr[k]) {
                return color[k];
                // }
            }
        }
    }


    getDeptDetailInfo(pval, pname, cval, cname) {
        let _this = this;
        let params = {
            bjlb_value: pval,
            bjlb_text: pname,
            bclx_value: cval,
            bclx_text: cname,
            year: _this._handlers['yearSituation'].find("option:selected").val()
        }
        let loadding = dsf.layer.loadding();
        let url = UrlSetting.getClassSituationDetail;
        dsf.http.request(url, params, "GET")
            .done(function (res) {
                if (res.success) {
                    _this.renderClassInfo(res.data);
                } else {
                    dsf.layer.message();
                }
            })
            .error(function (err) {
                dsf.layer.message();
                console.log(err)
            })
            .always(function () {
                dsf.layer.close(loadding);
            }).exec();
    }

    renderClassInfo(params) {
        let _str = "         <li>" +
            "                        <i class='icon-com icon-bjs'></i>" +
            "                        <div class='info-detail'>" +
            "                            <span class='til'>班级数</span>" +
            "                            <span class='num'>" + params.classCount + "</span>" +
            "                        </div>" +
            "                    </li>" +
            "                    <li>" +
            "                        <i class='icon-com icon-xys'></i>" +
            "                        <div class='info-detail'>" +
            "                            <span class='til'>学员数</span>" +
            "                            <span class='num'>" + params.xy_count + "</span>" +
            "                        </div>" +
            "                    </li>" +
            "                    <li>" +
            "                        <i class='icon-com icon-wbd'></i>" +
            "                        <div class='info-detail'>" +
            "                            <span class='til'>未报到</span>" +
            "                            <span class='num'>" + params.wbd_count + "</span>" +
            "                        </div>" +
            "                    </li>" +
            "                    <li>" +
            "                        <i class='icon-com icon-tx'></i>" +
            "                        <div class='info-detail'>" +
            "                            <span class='til'>退学</span>" +
            "                            <span class='num'>" + params.tx_count + "</span>" +
            "                        </div>" +
            "                    </li>";
        this._handlers['detailInfo'].html(_str);
    }


}