import dom from '../templates/TabList.ejs';
import {
    ControlEditor
} from "../../../editor/ControlEditor";
import {
    UrlSetting
} from "../../../core/pageAction";

import {map} from '../../../decorator/controlmap';

@map("学生选项卡",'teas.tablistclass','TabListClass')
export class TabListClass extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._idx = 0;
        this._isFir = true;
        this._desingerClass = ControlEditor;
    }


    initTemplate() {
        return dom(this);
    }

    createElement() {
        super.createElement();
        this.$tabtils = this._handlers['tabtils'];
        this.$tabcontent = this._handlers['tabcontent'];
    }

    renderContext() {
        super.renderContext();
        let _this = this;
        _this.tabListInit();
    }

    renderReady() {
        super.renderReady();
        let _this = this;
        this.element.find('.layui-tab').attr('lay-filter', 'tabs')
        layui.element.on('tab(tabs)', function (e) {
            if (e.index == this._idx) return;
            let code = e.elem.context.dataset.code;
            _this._idx = e.index;
            _this.getTabsInfo();
            let _path = dsf.Base64.encode('teas/xyxt/xyindex/views/dbList.html?str=' + code);
            _this._handlers['moreHref'].attr('href', dsf.url.getWebPath('teas/portals/views/main_strips.html?url=' + _path));
        });
    }

    renderComplete() {
        super.renderComplete();
    }

    tabListInit() {
        let _this = this;
        let tabList = [{
            tiltle: '待办提醒',
            code: ''
        },
        {
            tiltle: '教学评价',
            code: '20101,20102,20103,20104'
        },
        {
            tiltle: '通知公告',
            code: '20002'
        }
        ]
        let _tilsConetntStr = '';
        let _tabConetntStr = '';
        for (let i = 0; i < tabList.length; ++i) {
            let item = tabList[i];
            _tilsConetntStr += "<li data-code='" + item.code + "'>" + item.tiltle + "</li>";
            _tabConetntStr += "<div class='layui-tab-item'><ul class='tab-item-ul' id='J_tab_handle_li'></ul></div>";
        }
        this.$tabtils.html(_tilsConetntStr);
        this.$tabcontent.html(_tabConetntStr);
        $(this.$tabtils.find('li')[0]).addClass('layui-this');
        $(this.$tabcontent.find('.layui-tab-item')[0]).addClass('layui-show');

        if (!_this._root._isDesign) {
            _this.getTabsInfo();
            _this.getTotal();
            let _path = dsf.Base64.encode('teas/xyxt/xyindex/views/dbList.html?str=');
            _this._handlers['moreHref'].attr('href', dsf.url.getWebPath('teas/portals/views/main_strips.html?url=' + _path));
        }
    }
    getTotal() {
        let _this = this;
        let url = UrlSetting.getMainInfoTotal;
        dsf.http.request(url, {}, "GET")
            .done(function (res) {
                console.log(res)
                if (res.success) {
                    if (_this._isFir) {
                        $(_this.$tabtils.find('li')[0]).addClass('layui-this').append(`<span class="tab-all-num">${res.data}</span>`);
                        _this._isFir = false;
                    } else {
                        $(_this.$tabtils.find('li')[0]).find('.tab-all-num').html(`${res.data}`);
                    }
                } else {
                    dsf.layer.message(res.message);
                }
            })
            .error(function (err) {
                dsf.layer.message(err.message);
            })
            .always(function () {

            }).exec();
    }
    getTabsInfo() {
        let _this = this;
        let url = '';
        let loadding = dsf.layer.loadding();
        switch (_this._idx) {
            case 0:
                url = UrlSetting.getMainInfomationList + '?queryTypeStr=' + ''; //全部
                break;
            case 1:
                url = UrlSetting.getMainInfomationList + '?queryTypeStr=20101,20102,20103,20104';
                break;
            case 2:
                url = UrlSetting.getMainInfomationList + '?queryTypeStr=20002'; //通知公告
                break;
        }
        let params = {
            pageNumber: 1,
            pageSize: 5
        }
        dsf.http.request(url, params, "GET")
            .done(function (res) {
                console.log(res)
                if (res.success) {
                    _this.renderPage(res.data.list);
                } else {
                    dsf.layer.message(res.message);
                }
            })
            .error(function (err) {
                dsf.layer.message(err.message);
            })
            .always(function () {
                dsf.layer.close(loadding);
            }).exec();
    }

    renderPage(data) {
        let _this = this;
        let _contentWrap = $(_this.$tabcontent.find('.layui-tab-item')[_this._idx]).find('.tab-item-ul');
        if (data.length == 0) {
            _contentWrap.html("<img style='position: relative;top: 50px' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>");
        } else {
            let _innerStr = '';
            for (let i = 0; i < data.length; ++i) {
                _innerStr += "<li data-text='" + data[i].type_text + "' data-openW='" + data[i].exinfo + "' data-url='" + data[i].url + "'  data-status='" + data[i].status_value + "' data-id='" + data[i].dsfa_todo_id + "' class='" + (data[i].status_value == 1 ? 'hasRead' : '') + "'>" +
                    "       <div>" +
                    "           <p class='tab-item-ul-p'>" +
                    (_this._idx == 0 ? ("<span class='top-tab-item-til'>【" + data[i].type_text + "】</span>") : '') +
                    "               <span class='top-tab-item-msg'>" + (data[i].name !== null ? data[i].name : '') + "</span>" +
                    "           </p>" +
                    "           <p class='tab-item-ul-date'>" +
                    "               <span>" + (data[i][dsf.config.kw.createusername] !== null ? data[i][dsf.config.kw.createusername] : '') + "</span>" +
                    "               <span>" + dsf.date.format(new Date(data[i][dsf.config.kw.createtime]), 'yyyy-mm-dd') + "</span>" +
                    "           </p>" +
                    "        </div>" +
                    "       <div class='hideItem'>" +
                    "           <p class='tab-item-ul-p'>" +
                    (_this._idx == 0 ? ("<span class='top-tab-item-til'>【" + data[i].type_text + "】</span>") : '') +
                    "               <span class='top-tab-item-msg'>" + (data[i].name !== null ? data[i].name : '') + "</span>" +
                    "           </p>" +
                    "           <p class='tab-item-ul-date'>" +
                    "               <span>" + (data[i][dsf.config.kw.createusername] !== null ? data[i][dsf.config.kw.createusername] : '') + "</span>" +
                    "               <span>" + dsf.date.format(new Date(data[i][dsf.config.kw.createtime]), 'yyyy-mm-dd') + "</span>" +
                    "           </p>" +
                    "        </div>" +
                    "</li>"
            }
            _contentWrap.html(_innerStr);
            $(_this.$tabcontent.find('li').on('click', function () {
                let _url = $(this).attr('data-url');
                let _open = $(this).attr('data-openW');
                let _text = $(this).attr('data-text');
                let _hasReadUrl = UrlSetting.getMainInfomationListHasread;
                let _id = $(this).attr('data-id');
                let _status = $(this).attr('data-status');
                let $this = $(this);
                if (_status == 0) {
                    dsf.http.request(_hasReadUrl, {
                        dsfa_todo_id: _id
                    }, "POST")
                        .done(function (res) {
                            if (res.success) {
                                $this.addClass('hasRead');
                                _this.getTotal();
                                _this.getTabsInfo();
                            }
                        })
                        .error(function (err) {
                            dsf.layer.message(err.message);
                        })
                        .always(function () { }).exec();
                }
                if (_open !== 'null' && _text !== '通知公告') {
                    window.open(dsf.url.getWebPath(_url));
                    return;
                }
                if (_text == '作业提交') {
                    window.open(dsf.url.getWebPath(_url));
                    return;
                }
                dsf.layer.openDialog({
                    title: _text,
                    area: ['1200px', '620px'],
                    content: dsf.url.getWebPath(_url),
                    dialogLoaded: function (layero, index, win) { },
                });
            }))
        }
    }
}