import dom from '../templates/TeachNav.ejs';
import {
	ControlEditor
} from "../../../editor/ControlEditor";
import {
	UrlSetting
} from "../../../core/pageAction";

import {
	map
} from '../../../decorator/controlmap';

@map("教师导航栏", 'teas.teachnav', 'TeachNav')
export class TeachNav extends dsf.Controls.Control {
	constructor(id, isPart) {
		super(id, isPart);
		this.$showNavNum = null;
		this._desingerClass = ControlEditor;
		this.navStyle = "1";
		this.navHeight = "";
		this.hiddenSet = false;
		this.startIndex = "";
		this.liShowNum = null
	}

	set getNavNum(value) {
		// 可选择的最大数量
		this.$showNavNum = value;
	}

	get getNavNum() {
		return this.$showNavNum
	}

	initTemplate() {
		return dom(this);
	}

	createElement() {
		super.createElement();
	}

	renderContext() {
		super.renderContext();
		let _this = this;
		_this._handlers['nav'].css('width', window.innerHeight - 16);
		if (!_this.root._isDesign) {
			_this.root.event.on(PageEvent.READY, evt => {
				_this.getMenus();
			});
			_this.openSetting();
		}
	}

	renderStyle() {
		let col = this.navStyle;
		if (col == 3) {
			this.element.addClass('col3');
		} else {
			this.element.removeClass('col3');
		}
	}

	initEvent() {
		let _this = this;
	}

	renderReady() {
		super.renderReady();
	}

	renderComplete() {
		super.renderComplete();
		this.setNavHeight();
	}

	getMenus() {
		let _this = this;
		let url = UrlSetting.getPScMenuByUserID;
		let loadding = dsf.layer.loadding();
		dsf.http.request(url, {}, "GET")
			.done(function(res) {
				if (res.success) {
					_this.renderPage(res.data);
				} else {
					dsf.layer.message(res.message);
				}
			})
			.error(function(err) {
				dsf.layer.message(err.message);
			})
			.always(function() {
				dsf.layer.close(loadding);
			}).exec();
	}

	renderPage(data) {
      console.log(data)
		let _this = this;
		let _menusStr = '';
		if (!_this.liShowNum) {
			_this.liShowNum = _this.getNavNum;
		}
		if (data.length > 0) {
			let i = this.startIndex || 0;
			let allowShowLen = i * 1 + (_this.liShowNum || 0) * 1;
			for (; i < (data.length > allowShowLen ? allowShowLen : data.length); ++i) {
				//红网做法
				let url = dsf.url.getWebPath('teas/portals/views/main.html?url=' + dsf.Base64.encode(data[i].url));

				if (this.navStyle == '3') {
					url = dsf.url.getAbsolutePath(data[i].url);
				}

				_menusStr += "<li><a target='_blank' href='" + url + "'>";
				if (_this.navStyle != 3) {
					_menusStr += "	<i class='iconfont " + (data[i].scicon || "icon-icon_wangye") + "'></i>";
				} else {
					_menusStr += "	<img src='" + data[i].picture +
						"' onerror='javascript:this.src=\"/dsfa/res/dsf_styles/themes/img/nav_404.png\"'/>";
				}
				_menusStr += "		<span class='til'>" + data[i].NAME + "</span>"
				_menusStr += "</a></li>";
			}
		}
		if (this.navStyle == '3' && !this.hiddenSet) {
			_menusStr +=
				'<li handler="set"><img src="/dsfa/res/dsf_styles/themes/img/navAdd.png" alt="添加导航"><span class="til">添加</span></li>';
		}
		_this._handlers['menus'].html(_menusStr);
		if (this.navStyle == '3'){
			// 不为一列时执行
			this.changeli();
		}
	}
	setNavHeight() {
		let h = this.navHeight;
		this.element.css('height', h || 'auto');
	}
	changeli() {
		let allowShowNum = (this.liShowNum || 0) * 1;
		let colNum = this.navStyle;
		if (allowShowNum > 0 && this.navHeight && parseInt(this.navHeight)) {
			let $li = this._handlers.menus.find('li');
			let distance = parseInt(this.navHeight) - (Math.ceil(allowShowNum / colNum) * $li.height()) - 14;
			if (distance > 0) $li.css("padding", (distance / (Math.ceil(allowShowNum / colNum) * 2)) + "px 10px");
		}
	}

	openSetting() {
		let _this = this;
		_this.element.on("click", "[handler='set']", function() {
			dsf.layer.openDialog({
				title: "设置导航栏",
				area: ["780px", "550px"],
				content: dsf.url.getWebPath("dsfa/oua/views/shortcut.html?maxLength=" + _this.getNavNum)
			});
		})
		_this.element.on("error", "img", function() {
			this.src = "/dsfa/res/dsf_styles/themes/img/nav_404.png";
		});
	}
}
