import dom from '../templates/Recommend.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { UrlSetting } from "../../../core/pageAction";
import { map } from '../../../decorator/controlmap';

@map("推荐", 'teas.recommend', 'Recommend')
export class Recommend extends dsf.Controls.Control {
   constructor(id, isPart) {
      super(id, isPart);
      this._desingerClass = ControlEditor;
   }

   initTemplate() {
      return dom(this);
   }

   initEvent() {

   }

   createElement() {
      super.createElement();
   }

   renderContext() {
      super.renderContext();
      if (!this._root._isDesign) {
         this.getRecommendData();
         this._handlers['moreHref'].attr('href', dsf.url.getWebPath('teas/portals/views/main_strips.html?url=' + dsf.Base64.encode('dsfa/cms/content/views/listxycklb.html')))
      }
   }

   renderComplete() {
      super.renderComplete();
   }

   getRecommendData() {
      let _this = this;
      let loadding = dsf.layer.loadding();
      let url = UrlSetting.getRecommend;
      //13958011117

      // let url = UrlSetting.getApplicationJson;
      dsf.http.request(url, {}, "GET")
         .done(function (res) {
            console.log(res)
            if (res.success) {
               if (res.data.length !== 0) {
                  _this.renderPage(res.data)
               } else {
                  _this._handlers['recommendList'].html("<img style='position: relative;top: 50px' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>").css({ 'text-align': 'center' });
               }
            } else {
               dsf.layer.message();
            }
         })
         .error(function (err) {
            dsf.layer.message();
            console.log(err)
         })
         .always(function () {
            dsf.layer.close(loadding);
         }).exec();
   }

   renderPage(data) {
      let _idx = 0;
      let _recommendStr = '';
      // let _desStr = '';
      let _len = parseInt(this._handlers['recommendList'].innerWidth() / 12);
      let _words = _len * 3 - _len / 4;
      for (let i = 0; i < data.length; ++i) {
         let isDesc = '';
         data[i].content = data[i].content !== null ? (data[i].content.replace(/<[^>]+>|&[^>]+;/g, '').trim()) : '';
         data[i].desc = data[i].desc !== null ? data[i].desc : '';
         if (data[i].desc == '') {
            if (data[i].content !== '' && data[i].content.length > _words) {
               isDesc = data[i].content.substring(0, _words);
            } else {
               isDesc = data[i].content
            }
         } else {
            if (data[i].desc.length > _words) {
               isDesc = data[i].desc.substring(0, _words);
            } else {
               isDesc = data[i].desc
            }
         }
         _recommendStr += "<h3 class='re-til'>" + data[i].name + "</h3><p class='re-msg' >" + "<span>" + isDesc + "</span>" + "</p>"
      }
      this._handlers['recommendList'].html(_recommendStr);
      $(this._handlers['recommendList'].find('.re-til')[0]).addClass('curSty');
      $(this._handlers['recommendList'].find('.re-msg')[0]).show();
      this._handlers['recommendList'].find('.re-til').hover(function () {
         var k = $('.re-til').index($(this));
         if (_idx == k) return false;
         _idx = k;
         // $('.re-msg').slideUp().eq(_idx).slideDown();
         $('.re-msg').stop(true, true).slideUp('slow').eq(_idx).slideDown('slow');
         $(this).addClass('curSty').siblings().removeClass('curSty');
      });
      this._handlers['recommendList'].find('.re-til').click(function () {
         var idx = $('.re-til').index($(this));
         var item = data[idx];
         if (item.exurl_value == '1') {//0 非外链 1外链
            if (item.sourceurl) dsf.openUrl(1, dsf.url.getAbsolutePath(item.sourceurl));
         } else {
            var path = dsf.url.getWebPath('teas/cms/template/listTemplateContent?cmsId=' + item.dsfa_cms_content_id + '&code=' + item.code);
            dsf.openUrl(1, path)
         }
      });
   }
}