import dom from '../templates/PlayerPlugIn.ejs'
import { ControlEditor } from '../../../editor/ControlEditor';
import { relyFiles } from '../../../core/relyfiles';
//import { Action, UrlSetting } from '../../../core/pageAction';
//import { PageEvent } from '../../../core/ControlEvent';

import {map} from '../../../decorator/controlmap';

@map("播放器",'teas.playerplugin','PlayerPlugIn')
@relyFiles([
    'res/libs/jquery-ui/jquery-ui.min.css',
    'res/libs/jquery-ui/jquery-ui.min.js',
    'res/libs/ckplayer/ckplayer.js'
])
export class PlayerPlugIn extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = ControlEditor;

        // this._videoUrl = location.host + dsf.url.getWebPath('video/0fd02089-72f9-4224-a7ba-8dd653d7d86a/suoyin.m3u8');
        this._videoUrl = "http://10.128.2.103:8081/dsfa/video/20190321/8f9f150413ae42c7a10d0df2fa1cb267/40e14480bda448318d98797697d28d31.m3u8";
    }

    //初始化模版
    initTemplate() {
        return dom(this);
    }

    render() {
        let _this = this;
        super.render();

        let videoObject = {
            //playerID:'ckplayer01',//播放器ID，第一个字符不能是数字，用来在使用多个播放器时监听到的函数将在所有参数最后添加一个参数用来获取播放器的内容
            container: '#ds_player_cntr_'+this.id, //容器的ID或className
            variable: 'player', //播放函数名称
            loaded: 'loadedHandler', //当播放器加载后执行的函数
            loop: true, //播放结束是否循环播放
            //autoplay: true, //是否自动播放
            //duration: 500, //设置视频总时间
            //cktrack: 'material/srt.srt', //字幕文件
            config: '', //指定配置函数
            debug: true, //是否开启调试模式
            //flashplayer: true, //强制使用flashplayer
            drag: 'start', //拖动的属性
            seek: 0, //默认跳转的时间
            video: this._videoUrl,
            path:dsf.url.getWebPath('res/libs/ckplayer/')
        };
        let player = new ckplayer(videoObject);
    }

    // loadedHandler(a,b,c){
    //     debugger
    // }


}

