import * as Controls from './hc/controls/index_hw';
// import * as Controls from './hc/controls/index_anhui';
// import * as Controls from './hc/controls/index_jiangsu';
// import * as Controls from './hc/controls/index_pudong';
! function () {
   dsf.use("Controls", Controls);

   let periods = ["上午", "下午", "晚上"];
   let teas = {};
   teas["periods"] = periods;

   teas.periodSplit = function (quarter, time, config, isNight) {
      let result = [];
      let _time = {
         st: dsf.date.parse(time.sdate, "yyyy-mm-dd"),
         et: dsf.date.parse(time.edate, "yyyy-mm-dd")
      }
      let st = dsf.date.parse(time.sdate, "yyyy-mm-dd");
      let et = dsf.date.parse(time.edate, "yyyy-mm-dd");
      for (let d = st; d <= et; d = dsf.date.addDate(d, 1)) {
         let d_str = dsf.date.format(d, "yyyy-mm-dd");
         let p_arr = isNight ? dsf.teas.periods.slice(0, 2) : dsf.teas.periods;
         for (let i = 0; i < p_arr.length; i++) {
            let p_st = config[quarter + "_" + p_arr[i]].st;
            let p_et = config[quarter + "_" + p_arr[i]].et;
            let p_sdate = dsf.date.parse(d_str + " " + p_st, "yyyy-mm-dd hh:ii");
            let p_edate = dsf.date.parse(d_str + " " + p_et, "yyyy-mm-dd hh:ii");
            if (_time.st < p_edate && _time.et > p_sdate) {
               let obj = {
                  "date": d_str,
                  "period": p_arr[i],
                  "time": {
                     st: p_st,
                     et: p_et
                  }
               };
               result.push(obj);
            }
         }
      }
      return result;
   }

   //查询排课配置
   teas.queryConfig = function (callback) {
      // let _this = this;
      let data = {
         "pageNum": 1,
         "pageSize": 100,
         "query": JSON.stringify({ "searchValue": "" }),
         "order": JSON.stringify([]),
         "namespace": "teas.jwgl.sksjgl",
         "pageName": "list"
      }
      let url = dsf.UrlSetting.list_load;
      dsf.http.request(url, data, "GET")
         .done(response => {
            if (response.success) {
               let data = response.data;
               let config = {};
               for (let i = 0; i < data.length; i++) {
                  let d = data[i];
                  let key = d["teas_jwgl_sksjgl.xq"].text + "_" + d["teas_jwgl_sksjgl.wb"].text;
                  let st = d["teas_jwgl_sksjgl.kssj"].split(":");
                  let et = d["teas_jwgl_sksjgl.jssj"].split(":");
                  let value = {
                     st: st[0] + ":" + st[1],
                     et: et[0] + ":" + et[1]
                  }
                  config[key] = value;
               }

               callback(null, config)
            } else {
               callback(response, null)
            }
         })
         .error(response => {
            dsf.layer.message(dsf.prompt.loaddatafail, false);
            callback(response, null)
         })
         .exec();
   }


   dsf.extend("teas", teas);
}(dsf);
