import dom from '../templates/ClassRoom.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { UrlSetting } from "../../../core/pageAction";

import {map} from '../../../decorator/controlmap';

@map("I-课堂",'teas.classroom','ClassRoom')
export class ClassRoom extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this.$dateUrl = ''
        this._desingerClass = ControlEditor;
        this.defualtImgUrl = '/res/dsf_styles/themes/img/500.png';
        this.tabtil = [
            { TILNAME: '研讨问题', QUESNUM: 12 },
            { TILNAME: '导学资料', QUESNUM: 12 }
        ];
        this.classStauts = {
            1: "未开始",
            2: "正在进行",
            3: "已结束"
        }
    }

    changeHref() {
        this._handlers['more'].attr('href', this.$dateUrl)
    }

    initTemplate() {
        return dom(this);
    }

    createElement() {
        super.createElement();
        let _this = this;
        let _more = this._handlers['more'];
        this.$roomvideo = this._handlers['roomvideo'];
        this.$roomtab = this._handlers['roomtab'];
    }

    renderContext() {
        super.renderContext();
        if (!this._root._isDesign) {
            this.getClassRoomInitData();
        }
    }

    initEvent() {
        let _this = this;
    }

    renderReady() {
        // let _this = this;
        super.renderReady();
    }

    renderComplete() {
        super.renderComplete();
    }

    getClassRoomInitData() {
        let _this = this;
        let loadding = dsf.layer.loadding();
        let url = "";
        if (_this.isDesign) {
            url = dsf.url.getWebPath("teas/tempdata/classroomtempdata.json");
        } else {
            url = dsf.url.getWebPath("teas/ikt/iktgl/kcgl/iktNewAndYtwtAndDxzl");
        }
        dsf.http.request(url, {}, "GET")
            .done(function (res) {
                if (res.success) {
                    if(res.data){
                        _this.renderPage(res.data);
                    } else {
                        _this.$roomtab.html("<img style='position: relative;top: 50px' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>").css({ 'text-align': 'center' });
                    }

                } else {
                    _this.$roomtab.html("<img style='position: relative;top: 50px' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>").css({ 'text-align': 'center' });
                }
            })
            .error(function (err) {
                dsf.layer.message(err.message);
                console.log(err)
            })
            .always(function () {
                dsf.layer.close(loadding);
            }).exec();
    }

    createTabContent(TABLIST, TITLE, MSG, SEENUM, DATE) {
        let _liStr = "";
        let url = "";
        let target = ""
        for (let k = 0; k < TABLIST.length; ++k) {
            let item = TABLIST[k];
            if (MSG) {
                console.log(item)
                console.log(item['teas_ikt_dxzl.dxzlid'])
                _liStr += "<li>" +
                    "<a href='" + dsf.url.getWebPath('teas/ikt/iktxq/views/iktytwtzj.html?id=' + item['teas_ikt_ytwt.ytwtid'] + '&iktid=' + item['teas_ikt_ytwt.iktglid']) + "' target='_blank'>" +
                    "<dl class='midd-msg-item'>" +
                    "<dd class='msg-item-des'>" +
                    "<i class='iconfont icon-ln_jiantouyou itemIcon'></i>" +
                    "<span>" + item[TITLE] + "</span>" +
                    "</dd>" +
                    "<dd class='msg-item-count'>" +
                    "<div class='msg-item-count-num'>" +
                    "<a class='msg'><i class='icon-msg icon-msg-com'></i> <span>" + item[SEENUM] + "</span></a>" +
                    "<a><i class='icon-see icon-msg-com'></i><span>" + item[MSG] + "</span></a>" +
                    "</div>" +
                    "<span class='msg-item-date'>" + item[DATE] + "</span>" +
                    "</dd>" +
                    "</dl>" +
                    "</a>" +
                    "</li>";
            } else {
                if (item.type == 2) {
                    url = item.url
                    target = '_blank'
                } else {
                    url = dsf.url.getWebPath(item.url);
                    // target = '_self'
                    target = '_blank'
                }
                _liStr += "<li>" +
                    "<a href='" + url + "' target='" + target + "'>" +
                    "<dl class='midd-msg-item'>" +
                    "<dd class='msg-item-des'>" +
                    "<i class='iconfont icon-ln_jiantouyou itemIcon'></i>" +
                    "<span>" + item[TITLE] + "</span>" +
                    "</dd>" +
                    "<dd class='msg-item-count'>" +
                    "<div class='msg-item-count-num'>" +
                    "<a><i class='icon-msg icon-msg-com'></i><span>" + item[SEENUM] + "</span></a>" +
                    "</div>" +
                    "<span class='msg-item-date'>" + item[DATE] + "</span>" +
                    "</dd>" +
                    "</dl>" +
                    "</a>" +
                    "</li>";
            }
        }
        return _liStr
    }

    renderPage(data) {
        let datas = data[0];
        let dxzl = datas.dxzl;
        let ytwt = datas.ytwt;
        let TABLIST = "";
        let imgObj = JSON.parse(datas['teas_ikt_iktgl.scfm']);
        let imgsrc = !$.isEmptyObject(imgObj) ? dsf.url.getWebPath(imgObj[0].relativePath) : dsf.url.getWebPath(this.defualtImgUrl);
        let _roomvideoStr =
            "<div class='l-video-img-wrap'>" +
            "<img src=" + imgsrc + " alt='' width='248px' height='198px'  onerror=\"onerror=null;src='" + dsf.url.getWebPath(this.defualtImgUrl) + "'\">" +
            "<span class='l-video-station'>" + this.classStauts[datas['status']] + "</span>" +
            "</div>" +
            "<p class='l-con-video-msg'>授课老师: <span>" + datas['teas_ikt_iktgl.skls'] + "</span></p>" +
            "<p class='l-con-video-msg msg-small-size'>授课时间: <span>" + datas['teas_ikt_iktgl.sksj'] + "</span></p>";
        let _roomtabStr = '';
        let _allCoentStr = "<a target='_blank' href='" + dsf.url.getWebPath('teas/ikt/iktJh/views/ikt_detail.html?courseId=' + datas['teas_ikt_iktgl.id']) + "' class='tltle-icon-wrap til-more-sty'>进入I-课堂<i class='title-icon-more'></i></a>"
        let _roomconStr = '';
        let _item = "";
        for (let i = 0; i < this.tabtil.length; ++i) {
            let _num = i == 1 ? dxzl.length : ytwt.length;
            _roomtabStr += "<li>" + this.tabtil[i].TILNAME + "<span class='midd-til-num'>( " + _num + " )</span></li>";
            i == 0 ? TABLIST = ytwt : TABLIST = dxzl;
            if (i == 1) {
                _item = this.createTabContent(TABLIST, "bt", null, "lll", dsf.config.kw.createtime);//导学资料
            } else {
                _item = this.createTabContent(TABLIST, "teas_ikt_ytwt.ytwtbjbt", "teas_ikt_ytwt.ytwtplnum", "teas_ikt_ytwt.lll", "teas_ikt_ytwt.fbsj");//研讨问题
            }
            if (TABLIST.length > 0) {
                _roomconStr += "<div class='layui-tab-item'><ul class='midd-msg-list'>" + _item + "</ul></div>";
            } else {
                _roomconStr += "<div class='layui-tab-item'><p style='text-align: center;padding: 10px 0;'>暂无数据</p></div>";
            }

        }
        _roomconStr = "<div class='layui-tab-content'>" + _roomconStr + "</div>";
        _roomtabStr = "<ul class='layui-tab-title layui-default-midd'>" + _roomtabStr + "</ul>";

        let _roomContent = "<div class='layui-tab layui-tab-brief' lay-filter='J_top_tab'>" + _roomtabStr + _allCoentStr + _roomconStr + "</div>";

        this.$roomvideo.html(_roomvideoStr);

        this.$roomtab.html(_roomContent);

        $(this.$roomtab.find('.layui-tab-title li')[0]).addClass('layui-this');

        $(this.$roomtab.find('.layui-tab-content .layui-tab-item')[0]).addClass('layui-show');

        this.element.find('.layui-tab').attr('lay-filter', 'test')
        layui.element.on('tab(test)', function (e) {
        });
    }
}
