import dom from '../templates/MyClassRoom.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { UrlSetting } from "../../../core/pageAction";


import {map} from '../../../decorator/controlmap';

@map("我的I-课堂",'teas.myclassroom','MyClassRoom')
export class MyClassRoom extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this.$defualtImgUrl = ''
        this._desingerClass = ControlEditor;
        this.tabtil = [
            { TILNAME: '研讨问题', QUESNUM: 12 },
            { TILNAME: '导学资料', QUESNUM: 12 }
        ]
        this.classStauts = {
            1: "未开始",
            2: "正在进行",
            3: "已结束"
        }
    }

    initTemplate() {
        return dom(this);
    }

    createElement() {
        super.createElement();
        let _this = this;

        this.$myclassroomwrap = this._handlers.myclassroomwrap
    }

    renderContext() {
        super.renderContext();
        this.getClassRoomInitData();
    }

    initEvent() {
        let _this = this;
    }

    renderReady() {
        // let _this = this;
        super.renderReady();
    }

    renderComplete() {
        super.renderComplete();
    }

    getClassRoomInitData() {
        let _this = this;
        let loadding = dsf.layer.loadding();
        let url = UrlSetting.getMyClassRoom;
        if (_this.isDesign) {
            url = UrlSetting.getApplicationJson
        }

        dsf.http.request(url, {}, "GET")
            .done(function (res) {
                // _this.renderPage(res.CLASSROOM);
                _this.renderItem(res.data)
                if (res.success) {// renderData();} else {/dsf.layer.message(res.message);
                } else {
                    !_this.isDesign && dsf.layer.message(res.message)
                }
            })
            .error(function (err) {
                dsf.layer.message(err.message);
                console.log("errurl：UrlSetting.getMyClassRoom")
            })
            .always(function () {
                dsf.layer.close(loadding);
            }).exec();
    }
    renderItem(data) {
        let roomvideo = "";
        let roomtab = "";
        if (data.length > 0) {
            for (let i = 0; i < data.length; i++) {
                let contentwrap_html =
                    '<div class="class-room exre-height myclassroomItem" id="content_' + i + '">' +
                    '<div class="mc-m-cr-con" handler="roomitem">' +
                    '<div class="cr-con-l-video" handler="roomvideo"></div>' +
                    '<div class="cr-con-r-info" handler="roomtab"></div>' +
                    '</div>' +
                    '</div>'
                this.$myclassroomwrap.append(contentwrap_html)
                roomvideo = this.element.find('#content_' + i + ' .cr-con-l-video');
                roomtab = this.element.find('#content_' + i + ' .cr-con-r-info');
                this.renderPage(data[i], roomvideo, roomtab, i)
            }
        } else {
            let str = "<p style='text-align: center;padding: 10px 0;'>暂无数据</p>";
            this.$myclassroomwrap.append(str)
        }

    }
    createTabContent(TABLIST, TITLE, MSG, SEENUM, DATE) {
        // let _roomconStr = "";
        let _liStr = "";
        let url="";
        let target=""
        for (let k = 0; k < TABLIST.length; ++k) {
            let item = TABLIST[k];
            if (MSG) {
                _liStr += "<li>" +
                    "<a href='" + dsf.url.getWebPath('teas/ikt/iktxq/views/iktytwtzj.html?id=' + item['teas_ikt_ytwt.ytwtid']+ '&iktid=' + item['teas_ikt_ytwt.iktglid']) + "' target='_blank'>" +
                    "<dl class='midd-msg-item'>" +
                    "<dd class='msg-item-des'>" +
                    "<i class='iconfont icon-ln_jiantouyou itemIcon'></i>" +
                    "<span>" + item[TITLE] + "</span>" +
                    "</dd>" +
                    "<dd class='msg-item-count'>" +
                    "<div class='msg-item-count-num'>" +
                    "<a  class='msg'><i class='icon-msg icon-msg-com'></i> <span>" + item[SEENUM] + "</span></a>" +
                    "<a ><i class='icon-see icon-msg-com'></i><span>" + item[MSG] + "</span></a>" +
                    "</div>" +
                    "<span class='msg-item-date' style='display:inline-block;margin-left:20px'>" + item[DATE] + "</span>" +
                    "</dd>" +
                    "</dl>" +
                    "</a>" +
                    "</li>";
            } else {
                if (item.type == 2) {
                     url = item.url
                     target = '_blank'
                } else {
                    url = dsf.url.getWebPath(item.url);
                    //  target = '_blank'
                    target = '_blank'
                }
                _liStr += "<li>" +
                    "<a href='" + url + "' target='"+target+"'>" +
                    "<dl class='midd-msg-item'>" +
                    "<dd class='msg-item-des'>" +
                    "<i class='iconfont icon-ln_jiantouyou itemIcon'></i>" +
                    "<span>" + item[TITLE] + "</span>" +
                    "</dd>" +
                    "<dd class='msg-item-count'>" +
                    "<div class='msg-item-count-num'>" +
                    "<a ><i class='icon-msg icon-msg-com'></i><span>" + item[SEENUM] + "</span></a>" +
                    "</div>" +
                    "<span class='msg-item-date'  style='display:inline-block;margin-left:20px'>" + item[DATE] + "</span>" +
                    "</dd>" +
                    "</dl>" +
                    "</a>" +
                    "</li>";
            }

        }
        return _liStr
    }
    renderPage(datas, $roomvideo, $roomtab, index) {
        // let { VIDEO, TABLIST } = datas;
        let dxzl = datas.dxzl;
        let ytwt = datas.ytwt;
        let TABLIST = "";
        let imgObj = "";
        let enterUrl = dsf.url.getWebPath('teas/ikt/iktJh/views/ikt_detail.html?courseId=')
        if (!this.isDesign) {
            imgObj = JSON.parse(datas['teas_ikt_iktgl.scfm']);
        }

        let imgsrc = !$.isEmptyObject(imgObj) ? dsf.url.getWebPath(imgObj[0].relativePath) : dsf.url.getWebPath(this.$defualtImgUrl);
        let _roomvideoStr =
            "<div class='l-video-img-wrap'>" +
            "<img src=" + imgsrc + " alt='' width='248px' height='198px'>" +
            "<span class='l-video-station'>" + this.classStauts[datas['status']] + "</span>" +
            "</div>" +
            "<p class='l-con-video-msg'>授课老师: <span>" + datas['teas_ikt_iktgl.skls'] + "</span></p>" +
            "<p class='l-con-video-msg msg-small-size'>授课时间: <span>" + datas['teas_ikt_iktgl.sksj'] + "</span></p>";
        let _roomtabStr = '';
        let _allCoentStr = "<a href='" + enterUrl + datas['teas_ikt_iktgl.id'] + "' class='tltle-icon-wrap til-more-sty' target='_blank'>进入I-课堂<i class='title-icon-more'></i></a>"
        let _roomconStr = '';
        let _item = ""
        for (let i = 0; i < this.tabtil.length; ++i) {
            let _num = i == 1 ? dxzl.length : ytwt.length;
            _roomtabStr += "<li>" + this.tabtil[i].TILNAME + "<span class='midd-til-num'>( " + _num + " )</span></li>";
            i == 0 ? TABLIST = ytwt : TABLIST = dxzl;
            if (i == 1) {
                _item = this.createTabContent(TABLIST, "bt", null, "lll", dsf.config.kw.createtime);//导学资料
            } else {
                _item = this.createTabContent(TABLIST, "teas_ikt_ytwt.ytwtbjbt", "teas_ikt_ytwt.ytwtplnum", "teas_ikt_ytwt.lll", "teas_ikt_ytwt.fbsj");//研讨问题
            }
            if (TABLIST.length > 0) {
                _roomconStr += "<div class='layui-tab-item'><ul class='midd-msg-list'>" + _item + "</ul></div>";
            } else {
                _roomconStr += "<div class='layui-tab-item'><p style='text-align: center;padding: 10px 0;'>暂无数据</p></div>";
            }
        }
        _roomtabStr = "<ul class='layui-tab-title layui-default-midd'>" + _roomtabStr + "</ul>";
        _roomconStr = "<div class='layui-tab-content'>" + _roomconStr + "</div>";
        let _roomContent = "<div class='layui-tab layui-tab-brief' lay-filter='J_top_tab_" + index + "'>" + _roomtabStr + _allCoentStr + _roomconStr + "</div>";

        $roomvideo.html(_roomvideoStr);

        $roomtab.html(_roomContent);

        $($roomtab.find('.layui-tab-title li')[0]).addClass('layui-this');

        $($roomtab.find('.layui-tab-content .layui-tab-item')[0]).addClass('layui-show');

        // 点击tab页
        layui.element.on('tab(J_top_tab_' + index + ')', function (e) {
            let i = e.index;
            console.log(e)
            $($roomtab.find('.layui-tab-title li')[i]).addClass('layui-this');
            $($roomtab.find('.layui-tab-content .layui-tab-item')[i]).addClass('layui-show');
        });
    }
}
