import dome from '../templates/LeaveMsg.ejs';
import {ControlEditor} from "../../../editor/ControlEditor";
import {UrlSetting} from "../../../core/pageAction";
import {ItemMetaData} from '../../../core/metadata';

import {map} from '../../../decorator/controlmap';

const baseIndent = 60;

@map("留言",'teas.leavemsg','LeaveMsg')
export class LeaveMsg extends dsf.Controls.Control {
	constructor(id, isPart) {
		super(id, isPart);
		this._desingerClass = ControlEditor;
		this.$Msgtitle = "评论";
		this.MsgNum = "0";
		this.$businessType = "ikt-ytwt";
		this.$showpages = true;
		this.$indentNum = 2; //评论缩进数
		this.$userType = "student"
		this.commentContent = ""; //评论内容的父元素
		this.parentliId = "";
		this.allData = ""; //完成数据
		this.$metadata = ItemMetaData.call(this);
		this.$items = [];
		//与分页相关
		this._count = 0;
		this.$limit = 15;
		this._groups = 5;
		this._curr = 1;
		this._limits = [2, 5, 10, 15, 25, 30, 40, 50, 100];
		this.$source = "" //权限请求接口
		this.$isShowPagination = true
	}

	initTemplate() {
		return dome(this);
	}

	createElement() {
		super.createElement();
	}

	renderContext(refresh) {
		let _this = this;
		super.renderContext();
		this._handlers.Msgtitle.html(this.Msgtitle);

		// 分页的两种形式 1：layui分页，2：点击 "加载更多" 加载更多数据
		if (_this.$isShowPagination) {
			this._handlers.pages.attr("id", "comment_page")
		} else {
			this._handlers.pages.html("加载更多").attr("id", "loadMore").css("cursor", "pointer")
		}

		if (!refresh) {
			this.loadData(); //加载评论数据；
			if (this.$source) {
				this.alterRights()
			}
		}
	}
	initEvent() {
		let _this = this;
		if (!_this.$isShowPagination) {
			if (_this.count <= _this.$limit) {
				$("#loadMore").html("无更多数据");
				$('#loadMore').off('click')
			} else {
				$('#loadMore').on('click', function() {
					_this._curr++;
					_this.loadData(true)
				})
			}
		}
	}
	get items() {
		return this.$items;
	}
	set items(value) {
		this.$items = value;
	}
	set Msgtitle(val) {
		this.$Msgtitle = val
	}
	get Msgtitle() {
		return this.$Msgtitle
	}
	set isShowPagination(val) {
		this.$isShowPagination = val
	}
	get isShowPagination() {
		return this.$isShowPagination
	}
	set indentNum(val) {
		this.$indentNum = val
	}
	get indentNum() {
		return this.$indentNum
	}
	set businessType(val) {
		this.$businessType = val
	}
	get businessType() {
		return this.$businessType
	}

	set userType(val) {
		this.$userType = val
	}
	get userType() {
		return this.$userType
	}


	//分页属性 
	get pageSize() {
		return parseInt(this.$limit);
	}
	set pageSize(value) {
		this.$limit = parseInt(value);
	}

	set count(value) {
		this._count = value;
		renderPagination.call(this);
	}
	get count() {
		return this._count;
	}

	set groups(value) {
		this._showPageNum = value;
		renderPagination.call(this);
	}
	get groups() {
		return this._groups;
	}

	get curr() {
		return this._curr;
	}
	set curr(value) {
		this._curr = value;
	}

	renderReady() {
		super.renderReady();
		console.log("this.allData", this.allData)
		this.commentContent = this._handlers.msg_main; //评论内容父元素DIV
	}

	renderComplete() {
		super.renderComplete();
		$(".reply_btn").on("click", {
			obj: this
		}, this.replyfn)
	}
	getywlx(data) {
		let _this = this;
		let ywlxarr = _this.items;
		let ywlxobj = {};
		ywlxarr.forEach((obj, i) => {
			obj.value == _this.businessType && (ywlxobj = obj)
		});
		data.ywlx = ywlxobj;
		return data
	}
	loadData(isloadMore) {
		this.commentContent = this._handlers.msg_main
		let _this = this;
		let url = "";
		let args = "";
		let loadding = dsf.layer.loadding();
		if (_this.isDesign) {
			args = {}
			_this._handlers.msg_main.empty();
			url = dsf.url.getWebPath("teas/tempdata/leavemsg.json")
		} else {
			_this.parentliId = "";
			args = {
				businessType: _this.businessType,
				businessId: dsf.url.queryString("id"),
				level: _this.indentNum, //折叠层级
				pageNo: _this._curr,
				pageSize: _this.$limit,
				childNum: "100"
			}
			url = dsf.url.getWebPath("dsfa/comment/queryFistComHasUPhotoChildNumPage");
		}
		dsf.http.request_sync(url, args, "GET")
			.done(function(response) {
				console.log(response)
				if (response.success) {
					if (response.data && response.data.data) {
						_this.allData = _this.getywlx(response.data.data);
						if (response.data.data.length > 0) {
							_this.count = response.data.pageTotal;
							if (!isloadMore) {
								_this.commentContent.empty();
							}
							if(_this.count>_this.allData.length){
								$("#loadMore").html("加载更多");
							}
							// _this._handlers.MsgNum.html(response.data.total);
							_this.renderComment(_this.allData);
							_this.renderPagination();
						} else {
							if (_this.$isShowPagination) {
								_this.commentContent.html(
									"<img style='position: relative;top: 50px;margin-bottom: 50px;' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>"
								).css({
									'text-align': 'center'
								});
								_this._handlers.pages.empty();
							} else {
								$("#loadMore").html("无更多数据");
							}
						}
					}
				} else {
					dsf.layer.message("请求失败,请稍后再试", false)
				}
			})
			.error(function(err) {
				console.log(err);
				err && dsf.layer.message(err.data, false);
				_this.commentContent.html(
					"<img style='position: relative;top: 50px' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>").css({
					'text-align': 'center'
				});
				_this._handlers.pages.remove();
			})
			.always(function() {
				dsf.layer.close(loadding);
			}).exec();
	}
	//请求修改权限
	alterRights() {
		let args = {
			businessId: dsf.url.queryString("id"),
		}
		let url = dsf.url.getWebPath(this.$source);
		let _this = this;
		let loadding = dsf.layer.loadding();
		dsf.http.request(url, args, "GET")
			.done(function(response) {
				console.log(response)
				if (response.success) {
					if (response.isHandle) {
						_this.$userType = 'teacher'
					} else {
						_this.$userType = 'student'
					}
				} else {
					dsf.layer.message("请求失败,请稍后再试", false)
				}
			})
			.error(function(err) {
				dsf.layer.message("请求失败,请稍后再试", false)
			})
			.always(function() {
				dsf.layer.close(loadding);
			}).exec();
	}
	//非一级缩进
	indentItem(dom, level, subulId, data) {
		if (level > 1) {
			if (parseInt(this.indentNum) < 0 || parseInt(level) <= parseInt(this.indentNum)) {
				let dir = (level - 2) * 40 + baseIndent;
				$(dom).css("margin-left", dir + 'px');
			} else {
				let dir = (this.indentNum - 2) * 40 + baseIndent;
				$("#ul_" + subulId).css("margin-left", dir + 'px');
				let html = '<span style=""> 回复</span> <span class="name">' + data.bplr_text + '</span>'
				$("#ul_" + subulId + " .name").after(html)
			}
		}
	}
	//非一级评论(若嵌套评论 需要parentid)
	createSubItem(subData, parentid) {
		for (let k = 0; k < subData.length; k++) {
			//是否留言
			subData[k].isleavemsg = true;
			//是否点赞
			subData[k].iszan = true;
			!this.parentliId && (this.parentliId = subData[k].treeinfo_pid)
			let $lidom = $("#li_" + this.parentliId);
			let item = this.createItem(subData[k], k);
			$lidom.append(item);
			let $subUl = $("#ul_" + subData[k].dsfa_comment_id)
			$subUl.addClass('subcontent');

			//每条留言item绑定数据
			$("#msg_num_" + subData[k].dsfa_comment_id).data("data", subData[k]);
			//每条点赞item绑定数据
			$("#zan_num_" + subData[k].dsfa_comment_id).data("data", subData[k]);
			//刪除修改 綁定數據
			$("#operate_" + subData[k].dsfa_comment_id).data("data", subData[k])
			//是否有操作权限
			this.hasTools(subData[k])
			//控制子评论缩进
			this.indentItem($subUl, subData[k].treeinfo_level, subData[k].dsfa_comment_id, subData[k]);
			//递归生成子评论
			if (subData[k].hasOwnProperty('child') && subData[k].child.length > 0) {
				this.createSubItem(subData[k].child)
			}
			if (subData[k].is_dz == 1) {
				$('#zan_num_' + subData[k].dsfa_comment_id).find(".zanIcon").addClass("active")
			}
		}
	}
	//主方法——渲染评论
	renderComment(data) {
		for (let i = 0; i < data.length; i++) {
			//是否展开子集
			data[i].canclicktoggle = true;
			//是否留言
			data[i].isleavemsg = true;
			//是否点赞
			data[i].iszan = true;
			//创建一级评论
			let item = this.createItem(data[i], i);
			this.commentContent.append(item);
			if (data[i].is_dz == 1) {
				$('#zan_num_' + data[i].dsfa_comment_id).find(".zanIcon").addClass("active")
			}
			//是否有操作权限
			this.hasTools(data[i]);
			//操作按钮绑定数据
			$("#msg_num_" + data[i].dsfa_comment_id).data("data", data[i]);
			$("#zan_num_" + data[i].dsfa_comment_id).data("data", data[i]);
			$("#operate_" + data[i].dsfa_comment_id).data("data", data[i])

			//如果有二级评论--子评论大于2 收起全部
			/* if (data[i].hasOwnProperty('child') && data[i].child.length > 0) {
			     if (data[i].child.length < 2) {
			         this.parentliId = data[i].dsfa_comment_id
			         this.createSubItem(data[i].child);
			     } else {
			         //是否有展开全部评论
			         this.moreComment(data[i]);
			     }
			 }*/
			//如果有二级评论--全部展开
			if (data[i].hasOwnProperty('child') && data[i].child.length > 0) {
				// if (data[i].child.length < 2) {
				this.moreComment(data[i]);
				this.parentliId = data[i].dsfa_comment_id
				this.createSubItem(data[i].child);

				// } else {
				//     //是否展示所有子评论全部评论
				//     this.moreComment(data[i]);
				// }
			}
		}
		//绑定展开
		this.bindToggle();
		//绑定单条留言
		this.bindLeaveMsg();
		//绑定点赞方法
		this.bindZan();
		//绑定修改功能
		this.bindAlter();
		//绑定删除功能
		this.bindDelete()
	}
	//评论UL
	createItem(data, i) {
		let imgurl = "";
		if (data.zp && data.zp.length > 0) {
			let zp = JSON.parse(data.zp);
			if ($.isArray(zp)) {
				imgurl = zp[0].relativePath;
			}
		} else {
			imgurl = "res/dsf_styles/themes/img/default.png"
		}
		let html =
			'<ul class="msg_content" handler="msg_content" id="ul_' + data['dsfa_comment_id'] + '">' +
			'<li id="li_' + data['dsfa_comment_id'] + '">' +
			'<div class="msg_content_div_wrap">' +
			'<div class="msg_wrap">' +
			' <div class="head_wrap">' +
			'<img src="' + dsf.url.getWebPath(imgurl) + '"  class="head_icon">' +
			' </div>' +
			'<div class="name_item">' +
			'<div>' +
			'<span class="name">' + data.plr_text + '</span>' +
			'<span class="msg_time">' + data[dsf.config.kw.createtime] + '</span>' +
			'</div>' +
			'<div class="msg_sideInfo">' +
			'<div class="operate" id="operate_' + data['dsfa_comment_id'] + '" data-id="' + data['dsfa_comment_id'] +
			'" data-index="' + i + '"></div>' +
			'<div class="zan_num_wrap"  id="zan_num_' + data['dsfa_comment_id'] + '">' +
			'<i class="zanIcon icon"></i>' +
			'<span class="zan_num num">' + data.dzs + '</span>' +
			'</div>' +
			'<div class="msg_num_wrap"  id="msg_num_' + data['dsfa_comment_id'] + '" >' +
			// '<i class="msgIcon icon"></i>' +
			'<span class="msg_num num">回复</span>' +
			'</div>' +
			'</div>' +
			'</div>' +
			'<div class="msg">' +
			'<span class="plnr " id="content_span_' + data['dsfa_comment_id'] + '">' + data.plnr + '</span>' +
			'<textarea class="content_textarea" name=""  cols="5" rows="3"  id="content_textarea_' + data['dsfa_comment_id'] +
			'">' + data.plnr + '</textarea>' +
			'<div class="alter_submit" id="alter_submit_' + data['dsfa_comment_id'] + '">' +
			'<div class="alter_submit_btn alter_btn" id="alter_submit_btn_' + data['dsfa_comment_id'] + '">保存</div>' +
			'<div class="alter_close_btn alter_btn" id="alter_close_btn_' + data['dsfa_comment_id'] + '">取消</div>' +
			'</div>' +
			'</div>' +
			'</div>' +

			'</div>' +
			'<div class="toggle_wrap" id="toggle_' + data['dsfa_comment_id'] + '" data-index="' + i + '"></div>' +
			'<div class="reply_wrap" id="reply_msg_num_' + data['dsfa_comment_id'] + '" data-index="' + i + '"></div>' +
			'</li>' +
			'</ul>'
		return html;
	}
	appendTools(toolparentWrap) {
		let operateHtml = '<span class="alter">修改</span>' +
			'<span class="del">删除</span>'
		$(toolparentWrap).append(operateHtml)
	}
	appendToggle(toggleParentWrap) {
		// let toggleHtml = '<div class="toggle">展开全部评论</div>'
		let toggleHtml = '<div class="toggle">收起全部评论</div>'
		$(toggleParentWrap).append(toggleHtml)
	}
	appendReplyBox(replyboxWrap, data) {
		let replyboxHtml =
			'<div class="reply">' +
			'<textarea name="" id="" cols="5" rows="3"></textarea>' +
			'</div>' +
			'<div class="reply_submit">' +
			'<div class="reply_submit_btn reply_btn">提交</div>' +
			'<div class="reply_close_btn reply_btn">取消</div>' +
			'</div>'
		$(replyboxWrap).append(replyboxHtml);
		$(".reply>textarea").focus();
		this.bindReply(data);
	}
	//是否有操作权限
	hasTools(data) {
		if (this.userType == 'teacher' || (data.hasOwnProperty('is_own') && data.is_own == 1)) {
			let $toolparentWrap = $("#operate_" + data.dsfa_comment_id)
			this.appendTools($toolparentWrap)
		}
	}
	//是否有展开子评论功能
	moreComment(data) {
		if (data.hasOwnProperty('child') && data.child.length > 0) {
			let $toggleparentWrap = $("#toggle_" + data.dsfa_comment_id);
			this.appendToggle($toggleparentWrap)
		}
	}
	//展开功能
	bindToggle() {
		let _this = this;
		let data = _this.allData;
		$(".toggle_wrap").on("click", function(evt) {
			let currentTarget = evt.currentTarget;
			let target = evt.target;
			let targetIndex = $(currentTarget).attr("data-index");
			let itemData = data[targetIndex];
			//初始加载隐藏所有子评论
			/*if (itemData.canclicktoggle) {
			    itemData.canclicktoggle = !itemData.canclicktoggle;
			    if (itemData.hasOwnProperty('child') && itemData.child.length > 0) {
			        _this.parentliId = itemData.dsfa_comment_id
			        _this.createSubItem(itemData.child);
			    }
			    $(target).addClass("active");
			    //绑定单条留言
			    $(".msg_num_wrap").off("click");
			    _this.bindLeaveMsg();
			    _this.bindAlter();
			    //绑定点赞方法
			    _this.bindZan();
			    //绑定删除功能
			    _this.bindDelete()
			} else {
			    itemData.canclicktoggle = !itemData.canclicktoggle;
			    $(target).html("展开全部评论")
			    $(target).removeClass("active");
			    $(currentTarget).siblings(".subcontent").remove();
			}*/

			//初始加载显示全部子评论
			if (itemData.canclicktoggle) {
				itemData.canclicktoggle = !itemData.canclicktoggle;
				$(target).html("展开全部评论")
				$(target).removeClass("active");
				$(currentTarget).siblings(".subcontent").remove();
			} else {
				itemData.canclicktoggle = !itemData.canclicktoggle;
				$(target).html("收起全部评论")
				if (itemData.hasOwnProperty('child') && itemData.child.length > 0) {
					_this.parentliId = itemData.dsfa_comment_id
					_this.createSubItem(itemData.child);
				}
				$(target).addClass("active");
				//绑定单条留言
				$(".msg_num_wrap").off("click");
				_this.bindLeaveMsg();
				_this.bindAlter();
				//绑定点赞方法
				_this.bindZan();
				//绑定删除功能
				_this.bindDelete()
			}
		})
	}
	//留言功能
	bindLeaveMsg() {
		let _this = this;
		let data = "";
		$(".msg_num_wrap").on("click ", function(evt) {
			let target = evt.currentTarget;
			let id = $(target).attr("id");
			let $replyboxWrap = $("#reply_" + id);
			$(this).data("data") && (data = $(this).data("data"));

			$('.content_textarea').css("display", "none");
			$('.alter_submit').css("display", "none");
			$('.plnr').css("display", "initial")


			if ($("#reply_" + id + ":has(.reply)").length == 0) {
				$(target).addClass("isshowMsgBox");
			}
			if ($(target).hasClass('isshowMsgBox')) {
				_this.appendReplyBox($replyboxWrap, data);
				let uncloseId = data.dsfa_comment_id;
				$(".reply_wrap:not(#reply_msg_num_" + uncloseId + ")").empty();
				$(target).removeClass("isshowMsgBox");
			} else {
				$replyboxWrap.empty();
				$(target).addClass("isshowMsgBox")
			}
		})
	}
	//点赞功能
	bindZan() {
		let _this = this;
		let data = "";
		$('.zan_num_wrap').on("click", function(evt) {
			data = $(this).data("data");
			if (data.is_dz == 1) {
				dsf.layer.message("您已点赞，不能重复点赞")
				return
			}
			if (data.iszan) {
				let loadding = dsf.layer.loadding();
				let url = dsf.url.getWebPath("dsfa/comment/addOrCancelCommentZan")
				dsf.http.request(url, {
						dsfa_comment_id: data.dsfa_comment_id
					}, "POST")
					.done(function(response) {
						console.log(response)
						if (response.success) {
							data.iszan = !data.iszan;
							var dzs = parseInt(data.dzs)
							dzs++;
							$('#zan_num_' + data.dsfa_comment_id).find(".zan_num").html(dzs);
							$('#zan_num_' + data.dsfa_comment_id).find(".zanIcon").addClass("active")
						} else {
							dsf.layer.message(response.message)
						}
						_this.event.trigger(leaveMsgEvent.COUNTCHANGE, {
							ui: _this
						})
					})
					.error(function(err) {
						console.log(err);
						dsf.layer.message(err.message, false)
					})
					.always(function() {
						dsf.layer.close(loadding);
					}).exec();
			} else {
				dsf.layer.message("您已点赞，不能重复点赞")
			}
		})
	}
	//修改功能
	bindAlter() {
		let _this = this;
		$(".alter").on("click", function(evt) {
			let target = evt.target;
			let parentData = $(target).closest(".operate").data("data");
			let id = $(target).closest(".operate").attr("data-id");
			let textareaWidth = _this.resizeTextarea(id);
			// $("#content_textarea_" + id).val(parentData.plnr);
			//content_span_ce115f29e34d4f6ab93bc686ca231179
			let tempval = $('#content_span_' + id).text()
			$("#content_textarea_" + id).val(tempval);
			$("#content_span_" + id).css("display", "none");
			$("#content_textarea_" + id).css({
				"display": "initial",
				"width": textareaWidth
			}).focus();
			//判断是否有其他的修改窗口，有则隐藏
			let hasothertextarea = ($(".content_textarea:not(#content_textarea_" + id + ")").length > 0 && $(
				".content_textarea:not(#content_textarea_" + id + ")").css("display") != 'none');
			if (hasothertextarea) {
				dsf.layer.message("您还有一个评论正在编辑", false);
				$("#content_span_" + id).css("display", "initial");
				$("#content_textarea_" + id).css("display", "none");
				$("#alter_submit_" + id).css("display", "none");
				return;
			}
			$('.reply_wrap').empty();

			//修改的保存按钮
			$("#alter_submit_" + id).css({
				"display": "block",
				"width": textareaWidth
			});
			$("#alter_submit_btn_" + id).on("click", function() {
				$("#content_span_" + id).css("display", "initial");
				$("#content_textarea_" + id).css("display", "none");
				$("#alter_submit_" + id).css("display", "none");
				let newContent = $("#content_textarea_" + id).val();
				let args = {
					dsfa_comment_id: id,
					plnr: newContent
				}
				addOrRefreshComment.call(_this, args, function(response) {
					dsf.layer.message("修改成功", true);
					$("#content_span_" + id).html(newContent);
				})
			});
			//修改的关闭按钮
			$("#alter_close_btn_" + id).on("click", function() {
				$("#content_textarea_" + id).val("")
				$("#content_span_" + id).css("display", "initial");
				$("#content_textarea_" + id).css("display", "none");
				$("#alter_submit_" + id).css("display", "none")
			});
		})
	}
	//删除功能
	bindDelete() {
		let that = this;
		$(".del").on("click", function(evt) {
			let target = evt.target;
			let parentData = $(target).closest(".operate").data("data");
			let url = dsf.url.getWebPath('dsfa/comment/delComment');
			let args = {
				treeinfoGlobalid: parentData.treeinfo_globalid,
				businessType: that.allData.ywlx.value,
				businessId: dsf.url.queryString("id") || '25077e4a7dcc4b7f8ae6d3b6b8749020'
			}

			if ($("#content_textarea_" + parentData.dsfa_comment_id).css("display") != "none") {
				dsf.layer.message("编辑状态，无法删除", false);
				return
			}


			let loadding = dsf.layer.loadding();
			dsf.layer.confirm("是否要刪除当前评论", function() {
				dsf.http.request(url, args, "POST")
					.done(function(res) {
						if ($("#ul_" + parentData.dsfa_comment_id).hasClass('subcontent')) {
							$("#ul_" + parentData.dsfa_comment_id).siblings("ul").remove(); //非一级评论删除同辈
							that.loadData();
						}
						$("#ul_" + parentData.dsfa_comment_id).remove();
						console.log(res);
						$("[handler='MsgNum']").html(res.data.total);
						that.event.trigger(leaveMsgEvent.COUNTCHANGE, {
							ui: that
						})
						//加载分页控件
						if (that.$isShowPagination) {
							that._curr = Math.ceil(res.data.pageTotal / that.$limit);
							that.loadData();
						}
					})
					.error(function(res) {
						console.log("res 删除失败", res);
						dsf.layer.message("删除失败，请稍后再试", false)
					})
					.always(function() {
						dsf.layer.close(loadding);
					})
					.exec()
			})
			dsf.layer.close(loadding);
		})
	}
	//绑定回复功能
	bindReply(data) {
		let _this = this;
		$(".reply_submit_btn").on("click", function(evt) {
			_this.replyfn(null, data)
		})
		$(".reply_close_btn").on("click", function(evt) {
			$(this).closest(".reply_wrap").empty();
		})
	}
	//回复请求
	replyfn(evt, data) {
		let _this = this;
		let param = {};
		let args = {};
		var target = ""
		if ($('.reply_main textarea').val() && data) {
			$('.reply_main textarea').val("")
		}
		if (evt && evt.data && evt.data.obj) {
			var target = evt.data.obj;
			//主回复
			if (!($('.reply_main textarea').val())) {
				dsf.layer.message("请输入评论内容", false);
				return
			}
			param = {
				dsfa_comment_id: "",
				treeinfo_pid: ""
			}
		} else {
			//子回复
			target = _this
			if (!($('#reply_msg_num_' + data.dsfa_comment_id + ' .reply textarea').val())) {
				dsf.layer.message("请输入评论内容", false);
				return
			}
			param = {
				dsfa_comment_id: "",
				treeinfo_pid: data.dsfa_comment_id
			}
		}
		let tempargs = {
			plnr: $('.reply_main textarea').val() || $('#reply_msg_num_' + data.dsfa_comment_id + ' .reply textarea').val(),
			ywlx_text: data ? data.ywlx_text : target.allData.ywlx.text,
			ywlx_value: data ? data.ywlx_value : target.allData.ywlx.value,
			ywid: dsf.url.queryString("id"),
		}
		args = $.extend({}, param, tempargs);
		addOrRefreshComment.call(_this, args, function(response) {
			dsf.layer.message("评论成功", true);
			target.event.trigger(leaveMsgEvent.COUNTCHANGE, {
				ui: _this
			})
			if (evt && evt.data && evt.data.obj) {
				if(!target.$isShowPagination){
					target._curr = 1;
				}
				target.loadData();
				$('.reply_main textarea').val("")
			} else {
				//非一级回复
				let dataq = response.data;
				if (dataq.treeinfo_level <= 2) {
					target.parentliId = ""; //非嵌套样式的评论在第三级要沿用第2级的父id，故评论层级>3时不能清空父id
				}
				target.createSubItem([dataq]);
				$("#reply_msg_num_" + response.data.treeinfo_pid).empty();
				target.loadData();
			}
		})
	}
	//修改框宽度
	resizeTextarea(itemid) {
		let ulWidth = $("#ul_" + itemid).width();
		let headWidth = 62;
		let textareaWidth = ulWidth - headWidth + "px";
		return textareaWidth
	}
	renderPagination() {
		renderPagination.call(this);
	}
}

function renderPagination() {
	let id = 'comment_page';
	var laypage = layui.laypage;
	let _this = this;
	//执行一个laypage实例
	laypage.render({
		"elem": id,
		"count": this.count,
		"limit": parseInt(this.$limit),
		"limits": this._limits,
		"curr": this._curr,
		"groups": this._groups,
		"layout": ['prev', 'page', 'next', 'skip', 'count', 'limit'],
		"prev": "<i class='iconfont icon-left'></i>",
		"next": "<i class='iconfont icon-right'></i>",
		"jump": (obj, first) => {
			if (!first) {
				//如果pageSize发生变化
				_this.$limit = obj.limit;
				_this._curr = obj.curr;
				_this._groups = obj.groups;
				_this._count = obj.count;
				_this.loadData();
			}
		}
	});
}

function addOrRefreshComment(args, callback) {
	let url = dsf.url.getWebPath("dsfa/comment/addOrRefreshComment");
	let loadding = dsf.layer.loadding();
	dsf.http.request(url, args, "POST")
		.done(function(response) {
			console.log(response)
			if (response.success) {
				if (callback) callback(response)
			} else {
				dsf.layer.message(response.message, false)
			}
		})
		.error(function(err) {
			console.log(err);
			dsf.layer.message(err.message, false)
		})
		.always(function() {
			dsf.layer.close(loadding);
		}).exec();
}
