import dom from '../templates/Shortcuts.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { relyFiles } from '../../../core/relyfiles';
import { UrlSetting } from '../../../core/pageAction';

import { map } from '../../../decorator/controlmap';

@map("快捷栏", 'teas.shortcuts', 'Shortcuts')
@relyFiles([
   'res/libs/jquery-ui/jquery-ui.min.css',
   'res/libs/jquery-ui/jquery-ui.min.js'
])

export class Shortcuts extends dsf.Controls.Control {
   constructor(id, isPart) {
      super(id, isPart);
      this._desingerClass = ControlEditor;
      this._canScroll = true;
      this.maxLength = null;
   }
   initTemplate() {
      return dom(this)
   }

   menuBoxEvent() {
      // 右侧菜单事件
      let _this = this;
      let menu_box = _this._handlers['menu_box_' + _this.id];
      let menu_box_a = menu_box.find("a");
      let content_box = _this._handlers['content_box_' + _this.id];
      let trigger = _.debounce(function () {
         _this._canScroll = true;
      }, 600);
      // 点击高亮
      menu_box_a.on("click", function () {
         _this._canScroll = false;
         menu_box.find('.active').removeClass('active');
         $(this).addClass('active');
         trigger();
      })
      // 滚动高亮
      content_box.scroll(function () {
         if (_this._canScroll) {
            let top = $(this).offset().top - 26;
            let menu_a = menu_box.find("a");
            for (let i in menu_a) {
               let elem = menu_a[i];
               if (elem.getAttribute) {
                  let href = elem.getAttribute('href');
                  if ($(href).offset().top >= top) {
                     menu_box.find('.active').removeClass('active');
                     $(elem).addClass('active');
                     return;
                  }
               }
            }
         }
      })
   }
   choosedDivEvent() {
      // 已设置数据事件处理
      let _this = this;
      let content_div = _this._handlers['choosed_div_' + _this.id];

      // 拖拽排序
      content_div.sortable({
         cursor: "move",
         delay: "2",
         items: "div",
         opacity: 0.5,
         scroll: false,
         update: function (event, ui) {

         }
      });
      // 删除
      content_div.on('click', '.icon-shanchu1', function (event) {
         let elem = $(this).parents("div")[0];
         let id = elem.getAttribute("id").split("_")[0];
         elem.remove();
         $("#" + id).removeClass('choosed_');
      })
   }
   selectDivEvent() {
      // 选择数据
      let _this = this;
      let content_box = _this._handlers['content_box_' + _this.id];
      let content_div = _this._handlers['choosed_div_' + _this.id];

      content_box.find(".content>div").on("click", function () {
         if ($(this).hasClass("choosed_")) {
            $(this).removeClass('choosed_');
            $('#' + $(this).attr('id') + "_").remove();
         } else {
            if (_this.maxLength && content_div.find("div").length >= _this.maxLength) {
               dsf.layer.message("数量已达上限，最多只能设置" + _this.maxLength + "个", false);
               return;
            }
            let div = $(this).clone();
            div.attr("id", div.attr('id') + "_");
            content_div.append(div[0]);
            $(this).addClass('choosed_');
         }
      })
   }
   renderContext() {
      super.renderContext();
      let _this = this;

      let maxLength = dsf.url.queryString("maxLength");
      _this.maxLength = eval(maxLength) || _this.maxLength;

      loadData.call(_this);

      if (!_this.root._isDesign) {
         let content_div = _this._handlers['choosed_div_' + _this.id];
         // 关闭
         _this._handlers["close"].on("click", function () {
            _this.root.close();
         })
         // 保存
         _this._handlers["save"].on("click", function () {
            let array = []
            let divs = content_div.find("div");
            if (divs.length > _this.maxLength && _this.maxLength) {
               dsf.layer.message("数量已达上限，最多只能设置" + _this.maxLength + "个", false);
               return;
            }
            for (let i = 0; i < divs.length; i++) {
               let $elem = $(divs[i]);

               let id = $elem.attr("id").split("_")[0];
               let scicon = $elem.attr("scicon") == "null" ? null : $elem.attr("scicon");
               array.push({
                  id: id,
                  scicon: scicon,
                  order: i * 1 + 1,
                  NAME: $elem.attr("title")
               })
            }
            array = JSON.stringify(array);
            saveData.call(_this, array)
         })
         _this._handlers["reset"].on("click", function () {
            saveData.call(_this, "[]", true)
         })
      }
   }
}
function loadData() {
   let choosed_div = this._handlers['choosed_div_' + this.id];
   let content_box = this._handlers['content_box_' + this.id];
   let menu_box = this._handlers['menu_box_' + this.id]
   let layerIndex = dsf.layer.loadding();
   let requestOver = false;
   let choosed_data = [];
   if (choosed_div) {
      // 已设置的
      choosed_div.html("");
      dsf.http.request(UrlSetting.getPScMenuByUserID, "", "GET")
         .done(response => {
            if (response.success) {
               console.log(response);
               choosed_data = response.data;
               for (let i in response.data) {
                  let obj = response.data[i];
                  let div = $("<div title='" + obj.NAME + "' scicon='" + obj.scicon + "' id='" + obj.id + "_'></div>");
                  let img = $("<b class='iconfont " + (obj.scicon || "icon-icon_wangye") + "'></b>")
                  let i_gouxuan = $("<i class='iconfont icon-gouxuan'>");
                  let i_shanchu = $("<i class='iconfont icon-shanchu1'>");
                  div.append(img);
                  div.append(obj.NAME);
                  div.append(i_gouxuan);
                  div.append(i_shanchu);
                  choosed_div.append(div);
               }
               this.choosedDivEvent();
            } else {
               dsf.layer.message(dsf.prompt.loaddatafail, false);
            }
         })
         .error(response => {
            dsf.layer.message(dsf.prompt.loaddatafail, false);
         })
         .always(function () {
            if (requestOver) {
               dsf.layer.close(layerIndex);
               if (choosed_data) {
                  for (let i in choosed_data) {
                     let obj = choosed_data[i];
                     $("#" + obj.id).addClass("choosed_");
                  }
               }
            }
            requestOver = true;
         })
         .exec();
   }
   if (content_box) {
      // 可设置的
      content_box.find(".ds_label_box~.ds_label_box").remove();
      menu_box.find("a~a").remove();
      dsf.http.request(UrlSetting.getScMenuByUserID, "", "GET")
         .done(response => {
            console.log(response);
            if (response.success) {
               let a_box = [];
               for (let i in response.data) {
                  let obj = response.data[i];
                  if (obj.children && obj.children.length > 0) {
                     let id = this.id + "_" + a_box.length;
                     let box = $("<div id='" + id + "' class='ds_label_box ds_showColorLump'></div>");
                     let label = $("<label class='ds_label font_5 underline title'>" + obj._name + "</label>");
                     let div_box = $("<div class='content'></div>");
                     a_box.push({ id: id, name: obj._name });
                     for (let j in obj.children) {
                        let obj_s = obj.children[j];
                        let div = $("<div title='" + obj_s._name + "' id='" + obj_s._id + "' scicon='" + obj.scicon + "' ></div>");
                        let img = $("<b class='iconfont " + (obj_s.scicon || "icon-icon_wangye") + "'></b>")
                        let i_gouxuan = $("<i class='iconfont icon-gouxuan'>");
                        let i_shanchu = $("<i class='iconfont icon-shanchu1'>");
                        div.append(img);
                        div.append(obj_s._name);
                        div.append(i_gouxuan);
                        div.append(i_shanchu);
                        div_box.append(div);
                     }
                     box.append(label);
                     box.append(div_box);
                     content_box.append(box);
                     menu_box.append($("<a href='#" + id + "'>" + obj._name + "</a>"));
                  }
               }
               this.menuBoxEvent();
               this.selectDivEvent();

            } else {
               dsf.layer.message(dsf.prompt.loaddatafail, false);
            }
         })
         .error(response => {
            dsf.layer.message(dsf.prompt.loaddatafail, false);
         })
         .always(function () {
            if (requestOver) {
               dsf.layer.close(layerIndex);
               if (choosed_data) {
                  for (let i in choosed_data) {
                     let obj = choosed_data[i];
                     $("#" + obj.id).addClass("choosed_");
                  }
               }
            }
            requestOver = true;
         })
         .exec();
   }
}

function saveData(param, isReset) {
   let msg = isReset ? '重置' : '保存';
   let layerIndex = dsf.layer.loadding();
   let _this = this;
   dsf.http.request(UrlSetting.savePScMenu, { data: param }, "POST")
      .done(response => {
         if (response.success) {
            // window['parent'].page.event.trigger(PageEvent.READY);
            // window.page.event.trigger(PageEvent.READY);
            window.frameElement.opener.page.event.trigger(PageEvent.READY);
            if (isReset) {
               dsf.layer.message("重置成功，即将刷新...", true);
               setTimeout(function () {
                  window.location.reload();
               }, 1000)
            } else {
               dsf.layer.message(msg + "成功", true);
               setTimeout(function () {
                  window.parent.location.reload();
                  _this.root.close();
               }, 1000)
            }
         } else {
            dsf.layer.message(msg + "失败", false);
         }
      })
      .error(response => {
         dsf.layer.message(msg + "失败", false);
      })
      .always(function () {
         dsf.layer.close(layerIndex);
      })
      .exec();
}