import {
	RankMetaData,
	vattType
} from '../../../core/metadata';
import {
	map
} from '../../../decorator/controlmap';

@map("评价", 'teas.rank', 'Rank')
export class Rank extends dsf.Controls.RankControl {
	constructor(id, isPart) {
		super(id, isPart);
		this.$metadata = RankMetaData.call(this);
	}
	set value(v) {
		let _this = this;
		for (let i in this.rowSet.rows) {
			let index = (i * 1 + 1);
			this.rowSet.rows[i].score = v["pf_" + index];
			if (this.rowSet.rows[i].norm) {
				this.rowSet.rows[i].norm = v["bz_" + index];
			}
			if (this.rowSet.rows[i].weight) {
				this.rowSet.rows[i].weight = v["qz_" + index];
			}
			_.forEach(_this.rowSet.rows[i].children, function(_val, _key) {
				let _index = index + "_" + (_key * 1 + 1);
				_val.score = v["pf_" + _index];
				if (_val.norm) {
					_val.norm = v["bz_" + _index];
				}
				if (_val.weight) {
					_val.weight = v["qz_" + _index];
				}
			})
		}
		this.changeSelectValue();
	}
	get value() {
		let postData = {};
		let _data = this.rowSet.rows || [];
		let _metadata = this.metadata.valueAttributes;
		let _ri = 0;
		let _this = this;
		for (let r in _data) {
			let _d = _data[r];
			postData[_metadata[_ri].code] = _d.project;
			_ri++;
			if (this.rowSet.norm == "1") {
				postData[_metadata[_ri].code] = _d.norm;
				_ri++;
			}
			postData[_metadata[_ri].code] = _d.score;
			_ri++;
			if (this.rowSet.weight == "1") {
				postData[_metadata[_ri].code] = _d.weight;
				_ri++;
			}
			_.forEach(_d.children, function(_val, _key) {
				postData[_metadata[_ri].code] = _val.project;
				_ri++;
				if (_this.rowSet.norm == "1") {
					postData[_metadata[_ri].code] = _val.norm;
					_ri++;
				}
				postData[_metadata[_ri].code] = _val.score;
				_ri++;
				if (_this.rowSet.weight == "1") {
					postData[_metadata[_ri].code] = _val.weight;
					_ri++;
				}
			})
		}
		postData[_metadata[_metadata.length - 1].code] = this.rowSet.total;
		return postData;
	}
	createMetaData() {
		try {
			this.$metadata.valueAttributes = [];
			let _this = this;
			if (this.rowSet.level === '1') {
				for (let i in this.rowSet.rows) {
					let index = (i * 1 + 1);
					this.$metadata.valueAttributes.push({
						"name": "项目_" + index,
						"code": "xm_" + index,
						"length": "50",
						"unit": null,
						"defaultValue": _this.rowSet.rows[i].project,
						"type": $.extend({}, vattType["string"])
					});
					if (this.rowSet.norm == "1") {
						this.$metadata.valueAttributes.push({
							"name": "标准_" + index,
							"code": "bz_" + index,
							"length": "200",
							"unit": null,
							"defaultValue": _this.rowSet.rows[i].norm,
							"type": $.extend({}, vattType["string"])
						});
					}
					this.$metadata.valueAttributes.push({
						"name": "评分" + index,
						"code": "pf_" + index,
						"unit": null,
						"defaultValue": null,
						"length": "10",
						"type": $.extend({}, vattType["string"])
					});
					if (this.rowSet.weight == "1") {
						this.$metadata.valueAttributes.push({
							"name": "权重" + index,
							"code": "qz_" + index,
							"unit": null,
							"defaultValue": _this.rowSet.rows[i].weight,
							"length": "10",
							"type": $.extend({}, vattType["string"])
						});
					}
				}
			} else {
				let _this = this;
				_.forEach(_this.rowSet.rows, function(val, key) {
					let index = (key * 1 + 1);
					_this.$metadata.valueAttributes.push({
						"name": "一级项目_" + index,
						"code": "xm_" + index,
						"length": "50",
						"unit": null,
						"defaultValue": val.project,
						"type": $.extend({}, vattType["string"])
					});
					if (_this.rowSet.norm == "1") {
						_this.$metadata.valueAttributes.push({
							"name": "一级项目标准_" + index,
							"code": "bz_" + index,
							"length": "200",
							"unit": null,
							"defaultValue": val.norm,
							"type": $.extend({}, vattType["string"])
						});
					}
					_this.$metadata.valueAttributes.push({
						"name": "一级项目评分_" + index,
						"code": "pf_" + index,
						"unit": null,
						"defaultValue": null,
						"length": "10",
						"type": $.extend({}, vattType["string"])
					});
					if (_this.rowSet.weight == "1") {
						_this.$metadata.valueAttributes.push({
							"name": "一级项目权重" + index,
							"code": "qz_" + index,
							"unit": null,
							"defaultValue": val.weight,
							"length": "10",
							"type": $.extend({}, vattType["string"])
						});
					}
					if (val.children) {
						_.forEach(val.children, function(_val, _key) {
							let _index = (_key * 1 + 1);
							let index_test = "一级项目_" + index + "的二级项目";
							let _index_test = index + "_" + _index;

							_this.$metadata.valueAttributes.push({
								"name": index_test + "名",
								"code": "xm_" + _index_test,
								"length": "50",
								"unit": null,
								"defaultValue": _val.project,
								"type": $.extend({}, vattType["string"])
							});
							if (_this.rowSet.norm == "1") {
								_this.$metadata.valueAttributes.push({
									"name": index_test + "标准",
									"code": "bz_" + _index_test,
									"length": "200",
									"unit": null,
									"defaultValue": _val.norm,
									"type": $.extend({}, vattType["string"])
								});
							}
							_this.$metadata.valueAttributes.push({
								"name": index_test + "评分",
								"code": "pf_" + _index_test,
								"unit": null,
								"defaultValue": null,
								"length": "10",
								"type": $.extend({}, vattType["string"])
							});
							if (_this.rowSet.weight == "1") {
								_this.$metadata.valueAttributes.push({
									"name": index_test + "权重",
									"code": "qz_" + _index_test,
									"unit": null,
									"defaultValue": _val.weight,
									"length": "10",
									"type": $.extend({}, vattType["string"])
								});
							}
						})

					}
				})
			}
			this.$metadata.valueAttributes.push({
				"name": "总分",
				"code": "total",
				"unit": null,
				"defaultValue": null,
				"length": "10",
				"type": $.extend({}, vattType["string"])
			});

			if (this.metadata) {
				let key = this.root.scope;
				let controlCode = this.$caption;
				let ns = key;
				key += "." + controlCode;
				this.metadata.code = controlCode;
				this.metadata.id = ns.replace(/\_/g, '.') + "." + controlCode;
				let path = ns.replace(/\_/g, '.');
				this.metadata.at = path;
				this.metadata.name = this.metadata.name || this.label;
				this.metadata_fullcode = key;
				this.metadata.level = 0;
				return {
					"key": this.metadata_fullcode,
					"md": this.metadata
				};
			}
			return null;
		} catch (ex) {
			throw ex;
			return null;
		}
	}
	vaildateData() {
		let errors = [];
		if (this.$required || this.styleType == "3") {
			let index = 0;
			let _this = this;
			_.forEach(_this.rowSet.rows, function(val, key) {
				if (val.children && val.children.length > 0) {
					// 二级
					_.forEach(val.children, function(c_val, c_key) {
						if (_this.$required && c_val.score == null) {
							errors.push({
								"errorMsg": '此项必评',
								"index": index
							});
						} else if (_this.styleType == "3" && c_val.score * 1 > _this.chooseTypeInput * 1) {
							errors.push({
								"errorMsg": '此项评分为' + (_this.chooseTypeInput) + '分制,请正确评分',
								"index": index,
							});
						}
						index++;
					})
				} else {
					// 一级
					if (_this.$required && val.score == null) {
						errors.push({
							"errorMsg": '此项必评',
							"index": index
						});
					} else if (_this.styleType == "3" && val.score * 1 > _this.chooseTypeInput * 1) {
						errors.push({
							"errorMsg": '此项评分为' + (_this.chooseTypeInput) + '分制,请正确评分',
							"index": index
						});
					}
					index++;
				}
			})
		}
		return errors;
	}
}
