function loadData(callback) {
    let _this = this;
    let queue = dsf.queue(true);
    //教室信息查询
    queue.step((def, v) => {
        let postData = {
            classId: dsf.url.queryString('classid')
        }
        // let url = dsf.url.getWebPath('teas/xyxt/pzw/queryClassRowAndCol');
        let url = dsf.url.getWebPath(_this.querytabelDataAction);
        dsf.http.request(url, postData, "GET")
            .done(function (response) {
                console.log(response)
                if (response.success) {
                    // renderTable.call(_this, response.data)
                    _this.initCol = response.data.seat['colnum'] || 1;
                    _this.initRow = response.data.seat['rownum'] || 1;
                    def.resolve()
                } else {
                    _this.initCol = 1;
                    _this.initRow = 1;
                    def.reject();
                }
            })
            .error(function (response) {
                dsf.layer.message("获取教室信息失败", false);
                def.reject();
            }).exec();
    });


    //查询学员列表
    queue.step((def, v) => {
        let postData = {
            classId: dsf.url.queryString('classid')
        }
        def.resolve()
        // let url = dsf.url.getWebPath("teas/jwgl/bjxygl/edit/queryStusInfo");
        let url = dsf.url.getWebPath(_this.queryPersonAction)
        dsf.http.request(url, postData, "GET")
            .done(function (response) {
                console.log(response)
                if (response.success) {
                    _this.randomSeatsData = response.data;
                    // let _data = response.data;
                    // if (_this.isGrouped) {
                        let _data = fomartStudentsData(response.data)
                    // }
                    _this.studentsList = _data;
                    renderStudentsList.call(_this, _data)
                    def.resolve()
                } else {
                    def.reject();
                }
            })
            .error(function (response) {
                dsf.layer.message("获取教室信息失败", false);
                def.reject();
            }).exec();
    });

    queue.finally(() => {
        let colRow = {
            'teas_zygl_jsk.colnum': _this.initCol,
            'teas_zygl_jsk.rownum': _this.initRow
        }
        callback(colRow);
    })
    queue.exec();
}
