//格式化学员数据结构
function fomartStudentsData(list) {
    let data = []
    for (var i = 0; i < list.length; i++) {
        !list[i]["teas_jwgl_bjxygl.zb"].value ? list[i]["teas_jwgl_bjxygl.zb"] = { "text": "未分组", "value": 0 } : data[list[i]["teas_jwgl_bjxygl.zb"].text]
        if (!data[list[i]["teas_jwgl_bjxygl.zb"].value]) {
            var arr = [];
            arr.push(list[i]);
            data[list[i]["teas_jwgl_bjxygl.zb"].value] = arr;
        } else {
            data[list[i]["teas_jwgl_bjxygl.zb"].value].push(list[i])
        }
    }
    return data
}


function uniqStudent() {
    let studentTableDom = $(".table .studentbyId")
    let studentLisDom = $(".ds_studentslist .studentbyId")
    studentTableDom.each((i, el) => {
        let sId = $(el).attr("data-id")
        if (sId) {
            studentLisDom.each((i, el) => {
                let slisId = $(el).attr("data-id")
                if (sId == slisId) {
                    $(el).css("display", "none")
                }
            })
        }
    })
}
