function exchangeSeate(toSeatsObj, fromSeatsObj) {
    let toSeats = toSeatsObj.toSeatsData
    let fromSeats = fromSeatsObj.fromSeatsData

    console.log("toSeats", toSeats)
    console.log("fromSeats", fromSeats)
    if (toSeats === undefined || toSeats._id == fromSeats._id) {
        return
    }

    let toSeatsNum = toSeatsObj.toSeatsNum;
    let $toSeatsNumDom = $("[data_seatsnum=" + toSeatsNum + "]");
    addToTable.call(this, fromSeats, $toSeatsNumDom);

    if (!fromSeatsNum) {
        renderStudentsList.call(this, this.studentsList, toSeats['teas_jwgl_bjxygl.zb'].value)
        uniqStudent();
        return;
    }

    let $fromSeatsDom = $("[data_seatsnum=" + fromSeatsNum + "]");
    addToTable.call(this, toSeats, $fromSeatsDom);

    //保存被交换的座位
    let goBackSeat = {
        "name": toSeats['teas_jwgl_bjxygl.xm'],
        "classId": dsf.url.queryString("classid"),
        "xyzp": toSeats['teas_jwgl_bjxygl.zp'],
        "dwjzw": toSeats['teas_jwgl_bjxygl.dwjzw'],
        "zwh": fromSeatsNum.split('_')[0],
        "zwl": fromSeatsNum.split('_')[1],
        "xyid": toSeats['teas_jwgl_bjxygl.teas_jwgl_bjxygl_id'],
        "zb_text": toSeats['teas_jwgl_bjxygl.zb'].text,
        "zb_value": toSeats['teas_jwgl_bjxygl.zb'].value
    }
    saveStudentInfo(goBackSeat,this.saveStudentInfoAction);

    toSeats.zwh = goBackSeat.zwh;
    toSeats.zwl = goBackSeat.zwl;

    let toSeatsTmpDom = $('[data_seatsnum=' + toSeatsNum + ']').find("div.studentbyId")[0],
        fromSeatsTmpDom = $('[data_seatsnum=' + fromSeatsNum + ']').find("div.studentbyId")[0];

    $(toSeatsTmpDom).removeData("data");
    $(fromSeatsTmpDom).removeData("data");

    $(toSeatsTmpDom).data("data", fromSeats);
    $(fromSeatsTmpDom).data("data", toSeats);
    fromSeatsNum = '';
}