    getMyClassData() {
        let _this = this;
        let loadding = dsf.layer.loadding();
        let url = UrlSetting.getMyClassInfo;
        let params = {}
        dsf.http.request(url, params, "GET")
            .done(function (res) {
                if (res.success) {
                    if (res.data.length !== 0) {
                        _this.renderPage(res.data);
                    } else {
                        _this._handlers['classDetail'].html("<img style='position: relative;top: 35px' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>").css({
                            'text-align': 'center'
                        });
                        _this._handlers['MyClass'].parent('td').parent('tr').hide();
                        // _this._handlers['MyClass'].hide();
                    }
                } else {
                    dsf.layer.message();
                }
            })
            .error(function (err) {
                dsf.layer.message();
                console.log(err)
            })
            .always(function () {
                dsf.layer.close(loadding);
            }).exec();
    }

