//初始化加载，课程、活动
function loadData(callbak) {
    let _this = this;
    let queue = dsf.queue(true);

    //班次信息查询
    queue.step((def, v) => {
        let postData = {
            "data": JSON.stringify({
                "_id": _this._classId
            }),
            "pageName": "bcxx",
            "namespace": "teas.jwgl.pkgl.pkjk"
        }
        let url = UrlSetting.form_load;
        dsf.http.request(url, postData, "GET")
            .done(function (response) {
                if (response.success) {
                    if (!response.data._id) {
                        // dsf.layer.message("未查询到相关的班级信息", false);
                        def.reject();
                        _this._handlers.className.html("无班次");
                        return;
                    } else {
                        _this._classData = response.data;
                        let wspk = _this._classData["teas_jwgl_bjgl.wspk"];
                        if (wspk && wspk.value == "1") {
                            wjpkonoff.call(_this, "1", false);
                        }
                        _this._handlers.className.html(_this._classData["teas_jwgl_bjgl.name"] || "无班次");
                        if (_this._classData["teas_jwgl_bjgl.pxsj"] && _this._classData["teas_jwgl_bjgl.pxsj"].sdate) {
                            let date = dsf.date.parse(_this._classData["teas_jwgl_bjgl.pxsj"].sdate, "yyyy-mm-dd");
                            _this.year = date.getFullYear();
                            _this.month = date.getMonth();
                        }
                        def.resolve(_this._classData);
                    }
                } else {
                    def.reject();
                }
            })
            .error(function (response) {
                dsf.layer.message("班次信息查询出错", false);
                def.reject();
            }).exec();
    });

    queue.step(function (def, v) {
        queryClassCourse.call(_this, function (err, data) {
            if (err) {
                dsf.layer.message("初始化课程信息出现错误", false);
                def.reject();
            } else {
                _this._initData = data;
                def.resolve(v);
            }
        });
    })

    //查询上课时间配置信息
    queue.step((def, v) => {
        dsf.teas.queryConfig.call(_this, (err, data) => {
            if (err) {
                def.reject();
            } else {
                _this._planConfig = data;
                def.resolve();
            }
        })
    });

    if (!this.adjust) {
        //查询课程列表
        queue.step((def, v) => {
            queryClassList.call(_this, "", (err, data) => {
                if (err) {
                    def.reject();
                } else {
                    renderClassList.call(_this, data);
                    def.resolve();
                }
            })
        });
        //查询活动数据
        queue.step((def, v) => {
            queryActiveList.call(_this, "", (err, data) => {
                if (err) {
                    def.reject();
                } else {
                    renderActiveList.call(_this, data);
                    def.resolve();
                }
            })
        });
        //查询视频课程
        queue.step((def, v) => {
            queryVideoList.call(_this, "", (err, data) => {
                if (err) {
                    def.reject();
                } else {
                    renderVideoList.call(_this, data);
                    def.resolve();
                }
            })
        });
    }

    queue.finally(() => {
        checkPublishStatus.call(_this);
        callbak();
    })
    queue.exec();

}

