//验证课程是否冲突，并提示合班
function validateConflict(data, callback, exculedPkId) {
    let _this = this;
    let data1 = convertMetaData.call(this, data);
    let url = dsf.url.getWebPath("teas/jwgl/pkgl/pkxx/course/ctAndGx");
    let postData = {
        "classId": this._classData._id,
        "pkglId": data1._id || "",
        "data": JSON.stringify(data1)
    }
    callback = callback || dsf.noop;
    let queue = dsf.queue();
    queue.step(function (def, v) {
        dsf.http.request(url, postData, "POST")
            .done(function (response) {
                if (response.success) {
                    let list = (response.data.ctList || []).filter(function (o) {
                        if (exculedPkId) {
                            return o["teas_jwgl_pkgl_id"] != exculedPkId
                        }
                        return true;
                    })
                    def.resolve(list);
                } else {
                    dsf.layer.message("冲突验证出现错误", false);
                    def.reject();
                }
            })
            .error(function (response) {
                dsf.layer.message("冲突验证出现错误", false);
                def.reject();
            }).exec();
    });

    queue.step(function (def, v) {
        if (v.length > 0) {
            openConflict2.call(_this, v, data, function (result) {
                def.resolve(result);
            });
        } else {
            def.resolve("sure");
        }
    });
    queue.step(function (def, v) {
        callback ? callback(v) : dsf.noop();
        def.resolve();
    });
    queue.exec();
}

//将课程表数据转化为后台识别的元数据
function convertMetaData(data) {
    //转换为排课的元数据结构
    let data1 = {
        "teas_jwgl_pkgl.kcname": data.kcname,
        "teas_jwgl_pkgl.kc": $.isArray(data.kc) ? data.kc : [data.kc],
        "teas_jwgl_pkgl.jxxs": data.jxxs,
        "teas_jwgl_pkgl.skjs": data.skjs,
        "teas_jwgl_pkgl.sksj": data.sksj,
        "teas_jwgl_pkgl.sfpj": data.sfpj,
        "teas_jwgl_pkgl.skdd": $.isArray(data.skdd) ? data.skdd : [data.skdd],
        "teas_jwgl_pkgl.jxxs1": data.jxxs1,
        "teas_jwgl_pkgl.kcly": data.kcly,
        "teas_jwgl_pkgl.fbstatus": this._classData["teas_jwgl_bjgl.fbstatus"]
    };
    if (data.pkxx) {
        for (let i = 0; i < data.pkxx.length; i++) {
            let d = data.pkxx[i];
            d["teas_jwgl_pkgl_pkxx.kc"] = data1["teas_jwgl_pkgl.kc"];
            d["teas_jwgl_pkgl_pkxx.jxxs"] = data1["teas_jwgl_pkgl.jxxs"];
            d["teas_jwgl_pkgl_pkxx.skjs"] = data1["teas_jwgl_pkgl.skjs"];
            d["teas_jwgl_pkgl_pkxx.sksj"] = data1["teas_jwgl_pkgl.sksj"];
            d["teas_jwgl_pkgl_pkxx.sfpj"] = data1["teas_jwgl_pkgl.sfpj"];
            d["teas_jwgl_pkgl_pkxx.skdd"] = data1["teas_jwgl_pkgl.skdd"];
            d["teas_jwgl_pkgl_pkxx.xq"] = this._classData["teas_jwgl_bjgl.xq"];
        }
        data1["teas_jwgl_pkgl_pkxx"] = data.pkxx;
    }
    if (data.id != undefined) {
        data1._id = data.id
    }
    return data1;
}

