            //是否存在排课发布或取消发布的权限
            let startTime = dsf.date.parse(_this._classData["teas_jwgl_bjgl.pxsj"].sdate.split(" ")[0] + " 00:00:00");
            let currentDate = new Date();
            showPublishOrCancelPublish();
