//确认调课
function sureAdjust() {
    let _this = this;
    let queue = dsf.queue(true);
    let classCourse = null;
    queue.step(function (def, v) {
        queryClassCourse.call(_this, function (err, data) {
            if (err) {
                def.reject("操作失败");
            } else {
                classCourse = data;
                let ct = [];
                for (let i = 0; i < data.length; i++) {
                    if (data[i].ct.length > 0) {
                        ct.push(data[i]);
                    }
                }
                if (ct.length > 0) {
                    def.reject("课程存在冲突,请检查");
                } else {
                    def.resolve();
                }
            }
        });
    });
    queue.step(function (def, v) {
        let url = UrlSetting.sure_adjust;
        dsf.http.request(url, {
            classId: _this._classData._id
        }, "POST")
            .done(function (response) {
                if (response.success) {
                    dsf.layer.message("操作成功", true);
                    _this._initData = classCourse;
                    _this.event.trigger(CourseTableEvent.UPDATEADJUST, {
                        ui: _this,
                        "data": null
                    });
                    def.resolve();
                } else {
                    def.reject("操作失败")
                }
            })
            .error(function (response) {
                def.reject("操作失败")
            }).exec();
    });
    queue.catch(function (error) {
        dsf.layer.message(error, false);
    });
    queue.exec();

}

