/*拖动课程 */
let mouse = null,
    dropTD = null,
    currentDropElement = null,
    startDrag = function () {
        this.addClass("dragging");
        $(".ds_drop_high").removeClass("ds_drop_high");
    },
    stopDrag = function () {
        this.removeClass("dragging");
        $(".ds_drop_high").removeClass("ds_drop_high");
        mouse = null;
    },
    _drag = function (evt, ui, isAppend) {
        $(".ds_drop_high").removeClass("ds_drop_high");
        if (!mouse) {
            mouse = {};
        }
        currentDropElement = null;
        mouse.left = evt.pageX;
        mouse.top = evt.pageY;
        if (dropTD) {
            let dropElement = null;
            let tdRect = {
                "top": dropTD.offset().top,
                "left": dropTD.offset().left,
                "right": dropTD.offset().left + dropTD.outerWidth(),
                "bottom": dropTD.offset().top + dropTD.outerHeight()
            };
            if (!isAppend) {
                let classItems = dropTD.find(".ds_class_item");
                classItems.each(function (i, el) {
                    let cls = $(this);
                    let rect = {
                        "top": cls.offset().top,
                        "left": cls.offset().left,
                        "right": cls.offset().left + cls.outerWidth(),
                        "bottom": cls.offset().top + cls.outerHeight()
                    };
                    //说明拖拽到课程中
                    if (mouse.top >= rect.top && mouse.top < rect.bottom && mouse.left >= rect.left && mouse.left < rect.right) {
                        dropElement = cls;
                    }
                });
            }
            if (!dropElement) {
                if (mouse.top >= tdRect.top && mouse.top < tdRect.bottom && mouse.left >= tdRect.left && mouse.left < tdRect.right) {
                    dropElement = dropTD;
                }
            }
            if (dropElement) {
                currentDropElement = dropElement;
                dropElement.addClass("ds_drop_high");
                dropElement.find(".td_high_border").css({
                    width: dropElement.outerWidth(),
                    height: dropElement.outerHeight()
                });
            }
        }

    }

//拖动左侧课程列表
function dragLeftCourse(el) {
    let _this = this;
    el.draggable({
        "appendTo": "body",
        "revert": "invalid",
        "cursor": "move",
        "addClasses": false,
        "containment": "document",
        "disabled": this.disabled,
        "start": function (event, ui) {
            startDrag.call(_this);
        },
        "stop": function (event, ui) {
            stopDrag.call(_this)
        },
        "drag": function (event, ui) {
            _drag.call(_this, event, ui, true);
        },
        "helper": function (evt) {
            let target = $(evt.currentTarget);
            let w = target.width();
            let h = target.height();
            let kcname = el.data("data").kc[0].text;
            let jxxs = el.data("data").jxxs1.text;
            let proxy = $("<div><div class='ds_icon_5 title'>" + kcname + "</div><div>" + jxxs + "</div></div>");
            proxy.width(w);
            proxy.height(h);
            proxy.css({
                "padding": "10px",
                "border": "1px solid #E6E6E6",
                "zIndex": 9999,
                "opacity": 0.8,
                "backgroundColor": "#fff"
            });
            return proxy;
        }
    });
    if (!this.disabled) {
        el.attr("allow-drag") == "1" ? el.draggable("option", "disabled", false) : el.draggable("option", "disabled", true);
    }
}

//拖动已排课程
function dragCourse(el, div) {
    let _this = this;
    el.draggable({
        "addClasses": false,
        "appendTo": ".ds_schedule_wrap",
        "revert": "invalid",
        "cursor": "move",
        "containment": "window",
        "start": function (event, ui) {
            startDrag.call(_this);
        },
        "stop": function (event, ui) {
            stopDrag.call(_this);
        },
        "drag": function (event, ui) {
            _drag.call(_this, event, ui);
        },
        "disabled": _this.disabled || el.hasClass("dim"),
        "helper": function (evt) {
            let proxy = div.clone();
            proxy.addClass("ds_dragproxy").removeAttr("data-id").find(".ds_coursetable_tools").remove();
            proxy.width(div.width());
            return proxy;
        }
    });
}

//拖动放置课程
function dropCourse() {
    let _this = this;
    let dropElements = $("td.ds_day_content_td");
    let _drop = function (event, ui) {
        let target = $(ui.draggable);
        let currentInCell = target.closest(".ds_day_content_td");
        let dropTD = null;
        let kcdata = target.data("data");
        kcdata = $.extend(true, {}, kcdata);
        let dateCell = $(this);
        let time, dt;
        let default_skdd = _this._classData["teas_jwgl_bjgl.skdd"] || {
            "text": "",
            "value": ""
        };
        let isDropOnCourse = $(this).hasClass("ds_class_item");
        if (isDropOnCourse) {
            let td = $(this).closest('TD');
            dt = td.attr("d");
            time = getClassTime.call(_this, td.attr("period"));
            dropTD = td;
        } else {
            dt = dateCell.attr("d");
            time = getClassTime.call(_this, dateCell.attr("period"));
            dropTD = dateCell;
        }
        if (target.attr("event") == "drag") {
            //课程表之间互相拖动修改时间
            let isMoveCourse = false;
            let dropCourseData = null;
            if (currentDropElement) {
                //如果拖动到TD上则是在当前时间段追加课程否则就是交换
                currentDropElement.hasClass("ds_day_content_td") ? isMoveCourse = true : isMoveCourse = false;
                if (!isMoveCourse) {
                    //如果当前课程是被共享的课程不能交换
                    dropCourseData = currentDropElement.data("data");
                    if (kcdata.beShared.value == "1" || dropCourseData.beShared.value == "1") {
                        isMoveCourse = true;
                    }
                    if (!isMoveCourse) {
                        //判断课程是否只有半天课
                        let cls1 = $("div[data-id='" + kcdata.id + "']");
                        let cls2 = $("div[data-id='" + dropCourseData.id + "']");
                        if (cls1.length > 1 || cls2.length > 1) {
                            isMoveCourse = true;
                        }
                    }
                }
            }
            if (!isMoveCourse) {
                if (kcdata.id == dropCourseData.id) {
                    return false;
                }
                confirmCourseDragPos.call(_this, function (result) {
                    if (result == "exchange") {
                        if (kcdata.id != dropCourseData.id) {
                            exchangeCourse.call(_this, kcdata, dropCourseData, (err, data) => {
                                if (err) {
                                    dsf.layer.message(dsf.prompt.savefail, false);
                                } else {
                                    refreshCourse.call(_this);
                                }
                            });
                        }
                    } else {
                        if (currentInCell.get(0) != dropTD.get(0)) {
                            kcdata.sksj = {
                                sdate: dt + " " + time.st,
                                edate: dt + " " + time.et
                            };
                            moveCourse.call(_this, kcdata, (err, data) => {
                                if (err) {
                                    dsf.layer.message(dsf.prompt.savefail, false);
                                } else {
                                    refreshCourse.call(_this);
                                }
                            });
                        }
                    }
                });
            } else {
                if (currentInCell.get(0) != dropTD.get(0)) {
                    kcdata.sksj = {
                        sdate: dt + " " + time.st,
                        edate: dt + " " + time.et
                    };
                    moveCourse.call(_this, kcdata, (err, data) => {
                        if (err) {
                            dsf.layer.message(dsf.prompt.savefail, false);
                        } else {
                            refreshCourse.call(_this);
                        }
                    });
                }
            }
        } else {
            //从左侧课程表拖动到表格
            kcdata.skdd = [{
                "text": default_skdd.text,
                "value": default_skdd.value
            }]
            kcdata.sksj = {
                sdate: dt + " " + time.st,
                edate: dt + " " + time.et
            };
            kcdata.jxxs == "活动" ? kcdata.sfpj = {
                "text": "否",
                "value": "0"
            } : kcdata.sfpj = {
                "text": "是",
                "value": "1"
            };
            kcdata.stime = time.st;
            kcdata.etime = time.et;
            kcdata.pkxx = [{
                "teas_jwgl_pkgl_pkxx.teas_jwgl_bjgl_id": _this._classId,
                "teas_jwgl_pkgl_pkxx.bjname": _this._classData["teas_jwgl_bjgl.name"]
            }];
            let dindex = dsf.layer.loadding();
            validateConflict.call(_this, kcdata, function (result) {
                if (result == "sure") {
                    createCourse.call(_this, kcdata, (err, data) => {
                        if (err) {
                            dsf.layer.message(dsf.prompt.savefail, false);
                            dsf.layer.close(dindex)
                        } else {
                            delete kcdata.pkxx;
                            refreshCourse.call(_this, d => {
                                dsf.layer.close(dindex)
                            });
                        }
                    });
                } else {
                    dsf.layer.close(dindex)
                }
            });
        }
        return false;
    }

    dropElements.droppable({
        accept: function (a) {
            var t = $(this)
            if (isXGKC && !t.hasClass("timeout")) {
                return true;
            } else {
                let result = t.hasClass("timeout") || t.hasClass("overdue");
                return !result;
            }
        },
        tolerance: "pointer",
        greedy: true,
        over: function (event, ui) {
            dropTD = $(this);
            if (mouse) {

            }
        },
        drop: _drop
    });
}

