//拖动后提示冲突
function openConflict2(ctlist, data, callback) {
    let _this = this;
    let formData = convertMetaData.call(this, data)
    let btns = [{
        "text": "继续",
        "handler": function () {
            callback ? callback("sure") : dsf.noop();
            return true;
        }
    }, {
        "text": "取消",
        "handler": function () {
            callback ? callback("cancel") : dsf.noop();
            return;
        }
    }];
    let url = dsf.url.getWebPath("teas/views/conflict.html?classid=" + this._classData._id);
    let dialog = dsf.layer.openDialog({
        content: url,
        title: "课程存在冲突,请核实",
        area: ["800px", "550px"],
        closeBtn: 0,
        args: {
            "ctlist": ctlist,
            "classId": this._classData._id,
            "pdglId": data._id || "",
            "formData": formData,
            "callback": function (err, data) {
                dialog.closeWindow();
                callback ? callback("merge") : dsf.noop();
            }
        },
        btn: btns
    });
}

