import dom from "../templates/ZYChoice.ejs";
import { DataChoiceMetaData } from "../../../core/metadata";
import { isSupportDataPost } from "../../../core/postDecorator";
import * as ButtonPlugin from "../../../pulgins/buttons";
import { map } from "../../../decorator/controlmap";

@map("教室选择", "teas.zychoice", "ZYChoice")
@isSupportDataPost(true)
export class ZYChoice extends dsf.Controls.ItemsControl {
  constructor(id, isPart) {
    super(id, isPart);
    this.$placeholder = "请输入";
    this.label = "教学资源选择";
    this.value = [];
    this.$metadata = DataChoiceMetaData.call(this, 100);
    this.$dateSpace = "";
    this.$dialogUrl = "";
    // // this.$dialoSize = "1000px,600px";
    // // this.$dialogHeight = "600px";
    // // this.$dialogTitle = "请选择";
    this._buttonBar = ButtonPlugin.ButtonBar();
    this.maxTags = "";
    this._isTargetFormValueChange = true;
    this.newOpenDialogFn = null;
    this.disabledTrigger = null;
  }

  setDisabled(value) {
    this.disabled = !!value;
    if (this._handlers.input) {
      this._handlers.input.prop("disabled", this.disabled);
    }

    if (!this.disabled) {
      this.bindOpenDialogFn();
    } else {
      this.UntieOpenDialogFn();
      this.newOpenDialogFn = () => {
        if (this.disabledTrigger) this.disabledTrigger();
      };
      this.event.on("buttonbar_click", this.newOpenDialogFn);
    }
    console.log("disabled", value);
  }

  get label() {
    return super.label;
  }
  set label(value) {
    super.label = value;
  }

  set value(value) {
    if (value == undefined || value == null) {
      value = [];
    }
    if (typeof value == "string") {
      if (!value) {
        value = [];
      }
    }
    if (!$.isArray(value)) {
      value = [value];
    }
    let vcopy = value.slice(0);
    this._isTargetFormValueChange = false;
    this.clearTags(false);
    for (let i = 0; i < vcopy.length; i++) {
      let v = vcopy[i];
      if (JSON.stringify(v) != "{}") {
        if (
          (this.maxTags && i < parseInt(this.maxTags || 0)) ||
          !this.maxTags
        ) {
          this.addTag(v);
        }
      }
    }
    this._isTargetFormValueChange = true;
    if (this._handlers.readOnlyLabel) {
      this._handlers.readOnlyLabel.text(this.getTextString(","));
    }
  }
  get value() {
    return this.$value;
  }

  set placeholder(value) {
    this.$placeholder = value;
    if (this._handlers.input) {
      this._handlers.input.attr("placeholder", value);
    }
  }
  get placeholder() {
    return this.$placeholder;
  }

  initTemplate() {
    return dom(this);
  }

  createElement() {
    super.createElement();
    if (!this.readOnly) {
      let buttonArg = ""; //this.$dialogUrl + ";" + this.$dialogTitle + ";" + (this.$dialoSize.split(",").join(";"));
      let button = ButtonPlugin.createButton(
        "选择",
        "zychoice",
        "icon-Magnifier",
        "auxiliary",
        2,
        null,
        false,
        buttonArg
      );
      if (this._buttonBar.buttons.length <= 0) {
        this._buttonBar.buttons.push(button);
      }
      ButtonPlugin.renderButtons(
        this,
        this._handlers.searchBox,
        this._buttonBar,
        null,
        null,
        "small"
      );
    }
  }
  renderContext() {
    super.renderContext();
    if (this._handlers.input) {
      this._handlers.input.prop("disabled", this.disabled);
    }
    if (this._handlers.readOnlyLabel) {
      this._handlers.readOnlyLabel.text(this.getTextString(","));
    }
  }

  /**
   * 绑定弹窗事件
   */
  bindOpenDialogFn() {
    let _this = this;
    this.UntieOpenDialogFn();
    this.newOpenDialogFn = function(arg) {
      if (arg.actionName == "zychoice") {
        openSySelected.call(_this);
      }
    };
    this.event.on("buttonbar_click", this.newOpenDialogFn);
  }

  /**
   * 解除弹窗事件绑定
   */
  UntieOpenDialogFn() {
    if (this.newOpenDialogFn)
      this.event.off("buttonbar_click", this.newOpenDialogFn);
  }

  initEvent() {
    this.setDisabled(this.disabled);
  }

  renderReady() {
    super.renderReady();
  }

  renderComplete() {
    let _this = this;
    super.renderComplete();
    let trigger = _.debounce(function() {
      _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
      if (_this._handlers.input) {
        _this._handlers.input.trigger("change");
      }
    }, 200);

    if (this._handlers.input) {
      this._handlers.input.tagsinput({
        itemValue: "value",
        itemText: "text",
        freeInput: true,
        triggerChange: false,
        maxTags: this.maxTags || undefined,
      });
      this.element.find(".ds_tagsinput>input").prop("readonly", true);
      this._handlers.input.on("itemAdded", (evt) => {
        _this.$value = _this._handlers.input.tagsinput("items");
        if (_this._isTargetFormValueChange) {
          trigger();
        }
      });
      this._handlers.input.on("itemRemoved", (evt) => {
        _this.$value = _this._handlers.input.tagsinput("items");
        if (_this._isTargetFormValueChange) {
          trigger();
        }
      });
      // this.value = this.value;
    }
  }

  clearTags(isTrigger) {
    if (this._handlers.input) {
      this._handlers.input.tagsinput("removeAll");
    }
    this.$value = [];
    if (isTrigger != false) {
      this.event.trigger(FormControlEvent.VALUECHANGE, { ui: this });
    }
  }

  addTag(val) {
    if (this._handlers.input) {
      this._handlers.input.tagsinput("add", {
        value: val.value,
        text: val.text,
      });
    } else {
      let result = this.$value.filter((v, i) => {
        if (v.value == val.value) {
          v = val;
          return true;
        }
        return false;
      });
      if (result.length <= 0) {
        this.$value.push(val);
      }
    }
  }
  remove() {
    if (this._handlers.input) {
      this._handlers.input.tagsinput("destroy");
    }
    super.remove();
  }

  getTextString(split) {
    let arr = [];
    for (let i = 0; i < this.value.length; i++) {
      arr.push(this.value[i].text);
    }
    return arr.join(",");
  }

  getValueString(split) {
    let arr = [];
    for (let i = 0; i < this.value.length; i++) {
      arr.push(this.value[i].value);
    }
    return arr.join(split || ",");
  }
}

function openSySelected() {
  let _this = this;
  let title = "选择上课地点";
  let area = ["850px", "600px"];
  // let express=new dsf.Express();
  let args = {
    sd: "",
    ed: "",
    relid: "",
  };
  if (_this.root.getControl(_this.$dateSpace)) {
    let ctrl = _this.root.getControl(_this.$dateSpace).value;
    if (ctrl.sdate != undefined && ctrl.edate != undefined) {
      args.sd = ctrl.sdate;
      args.ed = ctrl.edate;
    } else {
      dsf.layer.message("监听的控件不是时间区间控件", false);
      return false;
    }
  }
  args.relid = dsf.url.queryString("id");
  _this.event.trigger("select_before", { ui: _this, args: args });
  let url = _this.$dialogUrl ? _this.$dialogUrl : "teas/views/zyselected.html";
  let state = "?";
  if (url.length - url.lastIndexOf(".html") > 5) {
    state = "&";
  }
  url = dsf.url.getWebPath(
    url +
      state +
      "max=" +
      _this.maxTags +
      "&relid=" +
      args.relid +
      "&sdate=" +
      args.sd +
      "&edate=" +
      args.ed
  );
  dsf.layer.openDialog({
    title: title,
    area: area,
    content: url,
    dialogLoaded: function(layero, index, win) {
      let data = $.extend(true, [], _this.value);
      if (win.setCheckedData) {
        win.setCheckedData(data);
      }
    },
    btn: [
      {
        text: "确定",
        handler: function(index, layero, win) {
          let max = null;
          if (_this.maxTags) {
            max = parseInt(_this.maxTags);
          }
          let result = win.getCheckedData();
          if (result != null && result != undefined) {
            result = $.isArray(result) ? result : [result];
            if (max && result.length > max) {
              dsf.layer.message("最多只能选择" + max + "个", false);
              return false;
            }
            _this.clearTags();
            for (let i = 0; i < result.length; i++) {
              let row = result[i];
              _this.addTag({ value: row.value, text: row.text });
            }
          }
        },
      },
      {
        text: "取消",
        handler: function(index, layero, win) {
          return true;
        },
      },
    ],
  });
}
